import { app, BrowserWindow, shell, ipcMain, session } from 'electron'
import { existsSync } from 'fs'
import { join } from 'path'
import { initSettingsDb, closeSettingsDb, getSettingJson, setSetting } from './services/settingsDb'
import { initIndexDb, closeIndexDb } from './services/indexDb'
import { ensureDocumentsFolderExists, isDocumentsFolderAccessible, rebuildIndexFromFolder, renameUuidSuffixedFiles } from './services/fileService'
import { ollamaManager } from './services/ollama'
import { registerDocumentHandlers } from './ipc/documents'
import { registerSettingsHandlers } from './ipc/settings'
import { registerCategoryHandlers } from './ipc/categories'
import { registerCitationHandlers } from './ipc/citations'
import { registerAiHandlers } from './ipc/ai'
import { registerExportHandlers } from './ipc/export'
import { registerOllamaHandlers } from './ipc/ollama'
import { registerDialogHandlers } from './ipc/dialog'
import { registerSnapshotHandlers } from './ipc/snapshots'
import { registerMigrationHandlers, checkAndRunMigration } from './ipc/migration'
import { registerImportHandlers } from './ipc/import'
import { registerSpellHandlers } from './ipc/spell'
import { registerSlidesHandlers } from './ipc/slides'
import { registerSlidesExportHandlers } from './ipc/slidesExport'
import { registerSlidesImportHandlers } from './ipc/slidesImport'
import { registerThumbnailHandlers } from './ipc/thumbnails'
import { registerFileAssociation } from './services/fileAssociation'
import { registerWindowHandlers, initPaths } from './ipc/windows'
import { windowChromeOptions, applyTitleBarOverlay } from './windowChrome'
import { autoUpdater } from 'electron-updater'

const APP_ICON = join(__dirname, '../../resources/icons/prose.ico')

// Pending file open from OS (before window is ready or while running)
let pendingFileOpen: string | null = null

interface SavedBounds { x: number; y: number; width: number; height: number; isMaximized: boolean }

function createMainWindow(): BrowserWindow {
  const saved = getSettingJson<SavedBounds | null>('windowBounds', null)
  const bounds = saved ?? { width: 1280, height: 800 }

  const win = new BrowserWindow({
    ...(saved?.x != null ? { x: saved.x, y: saved.y } : {}),
    width: bounds.width,
    height: bounds.height,
    minWidth: 960,
    minHeight: 600,
    ...windowChromeOptions(),
    show: false,
    autoHideMenuBar: true,
    ...(existsSync(APP_ICON) ? { icon: APP_ICON } : {}),
    webPreferences: {
      preload: join(__dirname, '../preload/index.js'),
      contextIsolation: true,
      nodeIntegration: false,
      sandbox: true,
    },
  })

  if (saved?.isMaximized) win.maximize()

  let boundsTimer: ReturnType<typeof setTimeout> | null = null
  function scheduleSaveBounds(): void {
    if (boundsTimer) clearTimeout(boundsTimer)
    boundsTimer = setTimeout(() => {
      if (win.isDestroyed()) return
      const b = win.getBounds()
      setSetting('windowBounds', JSON.stringify({ ...b, isMaximized: win.isMaximized() }))
    }, 500)
  }

  win.on('resize', scheduleSaveBounds)
  win.on('move', scheduleSaveBounds)
  win.on('close', () => {
    if (boundsTimer) { clearTimeout(boundsTimer); boundsTimer = null }
    if (!win.isDestroyed()) {
      const b = win.getBounds()
      setSetting('windowBounds', JSON.stringify({ ...b, isMaximized: win.isMaximized() }))
    }
  })

  win.on('ready-to-show', () => {
    win.show()
    if (pendingFileOpen) {
      win.webContents.send('app:open-file', pendingFileOpen)
      pendingFileOpen = null
    }
  })

  win.webContents.setWindowOpenHandler(({ url }) => {
    try {
      const parsed = new URL(url)
      const isExternal = (parsed.protocol === 'https:' || parsed.protocol === 'http:')
        && !parsed.hostname.endsWith('.internal')
      if (isExternal) shell.openExternal(url).catch(() => {})
    } catch { /* malformed URL — ignore */ }
    return { action: 'deny' }
  })

  win.webContents.on('will-navigate', (event, url) => {
    const devUrl = process.env['ELECTRON_RENDERER_URL']
    const allowed = devUrl ? url.startsWith(devUrl) : url.startsWith('file://')
    if (!allowed) event.preventDefault()
  })

  if (process.env['ELECTRON_RENDERER_URL']) {
    void win.loadURL(process.env['ELECTRON_RENDERER_URL'])
  } else {
    void win.loadFile(join(__dirname, '../renderer/index.html'))
  }

  return win
}

// Handle file-open events (macOS open-file / Windows second-instance)
app.on('open-file', (event, filePath) => {
  event.preventDefault()
  const focused = BrowserWindow.getFocusedWindow()
  if (focused && !focused.isDestroyed()) {
    focused.webContents.send('app:open-file', filePath)
  } else {
    pendingFileOpen = filePath
  }
})

// Handle second-instance (Windows/Linux: user double-clicked a .prose file while app running)
const gotLock = app.requestSingleInstanceLock()
if (!gotLock) {
  app.quit()
} else {
  app.on('second-instance', (_event, argv) => {
    // On Windows, the file path is passed as a command-line argument
    const filePath = argv.find((arg) => arg.endsWith('.prose'))
    const win = BrowserWindow.getAllWindows()[0]
    if (win) {
      if (win.isMinimized()) win.restore()
      win.focus()
      if (filePath) win.webContents.send('app:open-file', filePath)
    } else if (filePath) {
      pendingFileOpen = filePath
    }
  })
}

app.whenReady().then(async () => {
  // Prose never needs camera/mic/geolocation/notifications — deny every
  // permission request outright rather than relying on Electron's defaults.
  session.defaultSession.setPermissionRequestHandler((_wc, _permission, callback) => callback(false))

  // Register .prose file association so double-click works without an installer
  registerFileAssociation()

  try {
    initSettingsDb()
    initIndexDb()
    await ensureDocumentsFolderExists()

    // Rename legacy UUID-suffixed files and rebuild word counts in the
    // background. Runs async so it doesn't block window creation.
    void renameUuidSuffixedFiles().then(() => rebuildIndexFromFolder())

    registerDocumentHandlers()
    registerSettingsHandlers()
    registerCategoryHandlers()
    registerCitationHandlers()
    registerAiHandlers(ollamaManager)
    registerExportHandlers()
    registerOllamaHandlers(ollamaManager)
    registerDialogHandlers()
    registerSnapshotHandlers()
    registerMigrationHandlers()
    registerImportHandlers()
    registerSpellHandlers()
    registerSlidesHandlers()
    registerSlidesExportHandlers()
    registerSlidesImportHandlers()
    registerThumbnailHandlers()
    initPaths(
      join(__dirname, '../preload/index.js'),
      join(__dirname, '../renderer/index.html'),
      process.env['ELECTRON_RENDERER_URL'],
    )
    registerWindowHandlers()

    ipcMain.handle('documents:folderAccessible', () => isDocumentsFolderAccessible())

  } catch (err) {
    console.error('Startup error:', err)
    app.quit()
    return
  }

  createMainWindow()

  // Run migration after window is created so it can display progress
  checkAndRunMigration().catch((err) => {
    console.error('Migration check failed:', err)
  })

  const fileArg = process.argv.find((arg) => arg.endsWith('.prose') && arg !== process.execPath)
  if (fileArg) pendingFileOpen = fileArg

  if (app.isPackaged) {
    autoUpdater.autoDownload = false
    autoUpdater.autoInstallOnAppQuit = false
    autoUpdater.checkForUpdates().catch((err) => {
      console.error('Auto-update check failed:', err)
    })
  }

  void ollamaManager.start().catch((err) => {
    console.error('Ollama start error:', err)
  })

  app.on('activate', () => {
    if (BrowserWindow.getAllWindows().length === 0) createMainWindow()
  })
})

app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') app.quit()
})

app.on('will-quit', () => {
  ollamaManager.stop()
  closeSettingsDb()
  closeIndexDb()
})

import { ipcMain } from 'electron'
import { randomUUID } from 'crypto'
import { getIndexDb } from '../services/indexDb'

interface CategoryRow {
  id: string
  name: string
  color: string
  created_at: string
}

interface CategoryOut {
  id: string
  name: string
  color: string
  createdAt: string
}

const HEX_COLOR_RE = /^#[0-9a-fA-F]{6}$/

function rowToCategory(row: CategoryRow): CategoryOut {
  return { id: row.id, name: row.name, color: row.color, createdAt: row.created_at }
}

export function registerCategoryHandlers(): void {
  const db = () => getIndexDb()

  ipcMain.handle('categories:getAll', (): CategoryOut[] =>
    (db().prepare('SELECT * FROM categories ORDER BY name ASC').all() as CategoryRow[]).map(rowToCategory)
  )

  ipcMain.handle('categories:create', (_, data: unknown): CategoryOut => {
    if (!data || typeof data !== 'object') throw new Error('Invalid create payload')
    const d = data as Record<string, unknown>
    if (typeof d.name !== 'string' || !d.name.trim()) throw new Error('name is required')
    if (typeof d.color !== 'string' || !HEX_COLOR_RE.test(d.color)) throw new Error('color must be a hex color string')

    const id = randomUUID()
    const now = new Date().toISOString()
    db().prepare('INSERT INTO categories (id, name, color, created_at) VALUES (?, ?, ?, ?)').run(id, d.name.trim(), d.color, now)
    return rowToCategory(db().prepare('SELECT * FROM categories WHERE id = ?').get(id) as CategoryRow)
  })

  ipcMain.handle('categories:update', (_, id: unknown, data: unknown): CategoryOut => {
    if (typeof id !== 'string' || !id) throw new Error('Invalid category id')
    if (!data || typeof data !== 'object') throw new Error('Invalid update payload')
    const d = data as Record<string, unknown>
    const existing = db().prepare('SELECT * FROM categories WHERE id = ?').get(id) as CategoryRow | undefined
    if (!existing) throw new Error('Category not found')
    const name = typeof d.name === 'string' && d.name.trim() ? d.name.trim() : existing.name
    const color = typeof d.color === 'string' && HEX_COLOR_RE.test(d.color) ? d.color : existing.color
    db().prepare('UPDATE categories SET name = ?, color = ? WHERE id = ?').run(name, color, id)
    return rowToCategory(db().prepare('SELECT * FROM categories WHERE id = ?').get(id) as CategoryRow)
  })

  ipcMain.handle('categories:delete', (_, id: unknown): void => {
    if (typeof id !== 'string' || !id) throw new Error('Invalid category id')
    db().prepare('DELETE FROM categories WHERE id = ?').run(id)
  })
}

import { ipcMain } from 'electron'
import {
  createDocument,
  updateDocument,
  deleteDocument,
  resolveDocument,
  getAllDocumentsFromIndex,
  getFolderStats,
  changeDocumentsFolder,
  getDocumentsFolder,
  setDocumentsFolder,
  type ProseFileDocument,
} from '../services/fileService'
import { getAllIndexRows } from '../services/indexDb'
import { shell, dialog, BrowserWindow } from 'electron'
import { validateFolderPath } from '../lib/pathValidation'

const VALID_FORMATS = new Set(['none', 'mla', 'apa', 'chicago', 'ieee'])
const VALID_FILE_TYPES = new Set(['document', 'sheet', 'board', 'slides'])

function docToOut(doc: ProseFileDocument) {
  return {
    id: doc.id,
    title: doc.title,
    content: JSON.stringify(doc.content),
    format: doc.format,
    fileType: doc.fileType ?? 'document',
    wordCountGoal: doc.wordCountGoal,
    createdAt: doc.createdAt,
    updatedAt: doc.updatedAt,
    categoryId: doc.categoryId,
    headerContent: doc.headerContent != null ? JSON.stringify(doc.headerContent) : null,
    footerContent: doc.footerContent != null ? JSON.stringify(doc.footerContent) : null,
    pageMargins: doc.pageMargins ?? null,
  }
}

function dashboardDocToOut(doc: ReturnType<typeof getAllDocumentsFromIndex>[0]) {
  return {
    id: doc.id,
    title: doc.title,
    content: '{}',  // not used by the dashboard card (it uses pre-computed wordCount)
    format: doc.format,
    fileType: doc.fileType,
    wordCountGoal: null,
    createdAt: doc.createdAt,
    updatedAt: doc.updatedAt,
    categoryId: doc.categoryId,
    headerContent: null,
    footerContent: null,
    wordCount: doc.wordCount,
    hasThumbnail: doc.hasThumbnail,
  }
}

export function registerDocumentHandlers(): void {
  ipcMain.handle('documents:getAll', () => {
    return getAllDocumentsFromIndex().map(dashboardDocToOut)
  })

  ipcMain.handle('documents:getById', async (_, id: unknown) => {
    if (typeof id !== 'string' || !id) throw new Error('Invalid document id')
    const resolved = await resolveDocument(id)
    if (!resolved) return null
    return docToOut(resolved.doc)
  })

  ipcMain.handle('documents:create', async (_, data: unknown) => {
    if (!data || typeof data !== 'object') throw new Error('Invalid create payload')
    const d = data as Record<string, unknown>

    if (typeof d.title !== 'string' || !d.title.trim()) throw new Error('title is required')
    const fileType = typeof d.fileType === 'string' && VALID_FILE_TYPES.has(d.fileType) ? (d.fileType as 'document' | 'sheet' | 'board' | 'slides') : 'document'
    const format = typeof d.format === 'string' && VALID_FORMATS.has(d.format) ? d.format : 'none'
    const _wcg = d.wordCountGoal != null ? Number(d.wordCountGoal) : null
    const wordCountGoal = _wcg != null && isFinite(_wcg) ? Math.max(0, Math.min(999_999, Math.round(_wcg))) : null
    const categoryId = typeof d.categoryId === 'string' ? d.categoryId : null
    const headerContent = d.headerContent != null ? parseJsonField(d.headerContent) : null
    const footerContent = d.footerContent != null ? parseJsonField(d.footerContent) : null
    const pageMargins = isValidMargins(d.pageMargins) ? (d.pageMargins as { top: number; right: number; bottom: number; left: number }) : null

    let content: unknown = { type: 'doc', content: [] }
    if (typeof d.content === 'string' && d.content !== '{}') {
      try { content = JSON.parse(d.content) } catch { /* use empty */ }
    }

    const doc = await createDocument({
      title: d.title.trim(),
      fileType,
      format,
      content,
      headerContent,
      footerContent,
      pageMargins,
      wordCountGoal,
      categoryId,
    })

    return docToOut(doc)
  })

  ipcMain.handle('documents:update', async (event, id: unknown, data: unknown) => {
    if (typeof id !== 'string' || !id) throw new Error('Invalid document id')
    if (!data || typeof data !== 'object') throw new Error('Invalid update payload')
    const d = data as Record<string, unknown>

    const resolved = await resolveDocument(id)
    if (!resolved) throw new Error('Document not found')
    const { doc } = resolved

    const patch: Partial<ProseFileDocument> = {}

    if (typeof d.title === 'string' && d.title.trim()) {
      const newTitle = d.title.trim()
      const duplicate = getAllIndexRows().find(
        (r) => r.id !== id && r.title.toLowerCase() === newTitle.toLowerCase()
      )
      if (duplicate) throw new Error('DUPLICATE_TITLE')
      patch.title = newTitle
    }
    if (typeof d.format === 'string' && VALID_FORMATS.has(d.format)) patch.format = d.format
    if ('wordCountGoal' in d) {
      const _wcg2 = d.wordCountGoal != null ? Number(d.wordCountGoal) : null
      patch.wordCountGoal = _wcg2 != null && isFinite(_wcg2) ? Math.max(0, Math.min(999_999, Math.round(_wcg2))) : null
    }
    if ('categoryId' in d) patch.categoryId = typeof d.categoryId === 'string' ? d.categoryId : null
    if ('headerContent' in d) {
      patch.headerContent = d.headerContent != null ? parseJsonField(d.headerContent) : null
    }
    if ('footerContent' in d) {
      patch.footerContent = d.footerContent != null ? parseJsonField(d.footerContent) : null
    }
    if ('pageMargins' in d) {
      patch.pageMargins = isValidMargins(d.pageMargins) ? (d.pageMargins as { top: number; right: number; bottom: number; left: number }) : null
    }

    let snapshotOptions: { force?: boolean; label?: string | null } | undefined
    let newContent: unknown | undefined
    if (typeof d.content === 'string') {
      try { newContent = JSON.parse(d.content) } catch { newContent = doc.content }
      patch.content = newContent
      snapshotOptions = {
        force: d.forceSnapshot === true,
        label:
          typeof d.snapshotLabel === 'string' ? d.snapshotLabel :
          d.snapshotLabel === null ? null :
          undefined,
      }
    }

    const updatedDoc = await updateDocument(
      id,
      patch,
      snapshotOptions ? { snapshot: snapshotOptions } : undefined,
    )

    // Only a real content save should regenerate the thumbnail — title/format/
    // margin-only patches leave the rendered content (and its thumbnail) unchanged.
    // Sent back to the same renderer that owns the live editor DOM/canvas needed
    // to capture it, not broadcast to every window.
    if ('content' in patch) {
      event.sender.send('thumbnail:generate', id)
    }

    return docToOut(updatedDoc)
  })

  ipcMain.handle('documents:delete', async (_, id: unknown) => {
    if (typeof id !== 'string' || !id) throw new Error('Invalid document id')
    await deleteDocument(id)
  })

  ipcMain.handle('documents:getStorageInfo', async () => {
    return getFolderStats()
  })

  ipcMain.handle('documents:changeFolder', async (_event, newPath: unknown, moveFiles: unknown) => {
    if (typeof newPath !== 'string' || !newPath) throw new Error('Invalid folder path')
    validateFolderPath(newPath)
    const shouldMove = moveFiles === true
    await changeDocumentsFolder(newPath, shouldMove)
  })

  ipcMain.handle('documents:pickFolder', async (event) => {
    const win = BrowserWindow.fromWebContents(event.sender) ?? BrowserWindow.getFocusedWindow()
    const result = await dialog.showOpenDialog(win!, {
      title: 'Choose documents folder',
      defaultPath: getDocumentsFolder(),
      properties: ['openDirectory', 'createDirectory'],
    })
    if (result.canceled || !result.filePaths[0]) return null
    return result.filePaths[0]
  })

  ipcMain.handle('documents:setFolder', async (_, folder: unknown) => {
    if (typeof folder !== 'string' || !folder) throw new Error('Invalid folder')
    validateFolderPath(folder)
    setDocumentsFolder(folder)
  })

  ipcMain.handle('documents:openFolder', async () => {
    shell.openPath(getDocumentsFolder())
  })
}

function parseJsonField(value: unknown): unknown {
  if (typeof value === 'string') {
    try { return JSON.parse(value) } catch { return null }
  }
  if (typeof value === 'object') return value
  return null
}

function isValidMargins(v: unknown): boolean {
  if (!v || typeof v !== 'object') return false
  const m = v as Record<string, unknown>
  return ['top', 'right', 'bottom', 'left'].every((k) => typeof m[k] === 'number' && (m[k] as number) >= 0)
}

import { ipcMain, dialog, BrowserWindow } from 'electron'
import { extname } from 'path'
import {
  importProseFile,
  importMarkdownFile,
  importDocxFile,
  importSpreadsheetFile,
  importPptxFile,
  resolveDocument,
  type ProseFileDocument,
} from '../services/fileService'
import { getAllIndexRows } from '../services/indexDb'
import { validateImportFilePath } from '../lib/pathValidation'

const IMPORT_EXTS = [
  '.prose',
  '.md',
  '.markdown',
  '.docx',
  '.xlsx',
  '.xls',
  '.csv',
  '.pptx',
  '.ppt',
]

const IMPORT_DIALOG_FILTERS: Electron.FileFilter[] = [
  {
    name: 'All supported',
    extensions: ['prose', 'md', 'markdown', 'docx', 'xlsx', 'xls', 'csv', 'pptx', 'ppt'],
  },
  { name: 'Prose files', extensions: ['prose'] },
  { name: 'Documents', extensions: ['md', 'markdown', 'docx'] },
  { name: 'Spreadsheets', extensions: ['xlsx', 'xls', 'csv'] },
  { name: 'Presentations', extensions: ['pptx', 'ppt'] },
]

function docToOut(doc: ProseFileDocument) {
  return {
    id: doc.id,
    title: doc.title,
    content: JSON.stringify(doc.content),
    format: doc.format,
    fileType: doc.fileType ?? 'document',
    wordCountGoal: doc.wordCountGoal,
    createdAt: doc.createdAt,
    updatedAt: doc.updatedAt,
    categoryId: doc.categoryId,
    headerContent: doc.headerContent != null ? JSON.stringify(doc.headerContent) : null,
    footerContent: doc.footerContent != null ? JSON.stringify(doc.footerContent) : null,
  }
}

async function importOneFile(filePath: string): Promise<ProseFileDocument> {
  const ext = extname(filePath).toLowerCase()
  if (ext === '.prose') return importProseFile(filePath)
  if (ext === '.md' || ext === '.markdown') return importMarkdownFile(filePath)
  if (ext === '.docx') return importDocxFile(filePath)
  if (ext === '.xlsx' || ext === '.xls' || ext === '.csv') return importSpreadsheetFile(filePath)
  if (ext === '.pptx' || ext === '.ppt') return importPptxFile(filePath)
  throw new Error(`Unsupported file type: ${ext}`)
}

export function registerImportHandlers(): void {
  // Called with explicit file paths (drag-and-drop) or no args (opens picker)
  ipcMain.handle('documents:importFiles', async (event, filePaths: unknown) => {
    let paths: string[]

    if (Array.isArray(filePaths) && filePaths.every((p) => typeof p === 'string')) {
      paths = (filePaths as string[]).map((p) => {
        validateImportFilePath(p, IMPORT_EXTS)
        return p
      })
    } else {
      const win = BrowserWindow.fromWebContents(event.sender) ?? BrowserWindow.getFocusedWindow()
      const result = await dialog.showOpenDialog(win!, {
        title: 'Import files',
        filters: IMPORT_DIALOG_FILTERS,
        properties: ['openFile', 'multiSelections'],
      })
      if (result.canceled || !result.filePaths.length) return { imported: [], errors: [] }
      paths = result.filePaths
    }

    const results: ReturnType<typeof docToOut>[] = []
    const errors: string[] = []

    for (const filePath of paths) {
      try {
        const doc = await importOneFile(filePath)
        results.push(docToOut(doc))
      } catch (err) {
        errors.push(`${filePath}: ${(err as Error).message}`)
        console.error('[import] Failed to import', filePath, err)
      }
    }

    return { imported: results, errors }
  })

  // Open a .prose file by path (used by file association handler in main/index.ts)
  ipcMain.handle('documents:openByPath', async (_, filePath: unknown) => {
    if (typeof filePath !== 'string') throw new Error('Invalid path')
    validateImportFilePath(filePath, ['.prose'])

    // If already in index, return existing doc
    for (const row of getAllIndexRows()) {
      if (row.file_path === filePath) {
        const resolved = await resolveDocument(row.id)
        if (resolved) return docToOut(resolved.doc)
      }
    }

    // Not in index — import it
    const doc = await importProseFile(filePath)
    return docToOut(doc)
  })
}

import { ipcMain } from 'electron'
import { getSettingsDb } from '../services/settingsDb'

interface AppSettingsOut {
  theme: 'dark' | 'light'
  defaultFormat: string
  wordCountExcludesHeader: boolean
  defaultWordCountGoal: number | null
  ollamaModel: string
  pomodoroWorkMinutes: number
  pomodoroBreakMinutes: number
  musicVolume: number
  ambientVolumes: Record<string, number>
  typewriterMode: boolean
  editorFontFamily: string
  editorFontSize: number
  headingFontSizes: { h1: number; h2: number; h3: number }
  lightAccentColor: string | null
  darkAccentColor: string | null
  uiScale: number
  slidesRightPanelWidth: number
}

const DEFAULTS: AppSettingsOut = {
  theme: 'dark',
  defaultFormat: 'none',
  wordCountExcludesHeader: true,
  defaultWordCountGoal: null,
  ollamaModel: 'llama3.2:3b',
  pomodoroWorkMinutes: 25,
  pomodoroBreakMinutes: 5,
  musicVolume: 45,
  ambientVolumes: {},
  typewriterMode: false,
  editorFontFamily: 'Calibri',
  editorFontSize: 12,
  headingFontSizes: { h1: 36, h2: 24, h3: 18 },
  lightAccentColor: '#2563eb',
  darkAccentColor: '#60a5fa',
  uiScale: 110,
  slidesRightPanelWidth: 340,
}

const VALID_FORMATS = new Set(['none', 'mla', 'apa', 'chicago', 'ieee'])
const VALID_THEMES = new Set(['dark', 'light'])
const VALID_FONTS = new Set(['Calibri', 'Arial', 'Times New Roman', 'Georgia', 'Garamond', 'Courier New'])
const HEX_COLOR = /^#[0-9a-fA-F]{6}$/
const APP_SETTING_KEYS = new Set(Object.keys(DEFAULTS))

function validateSettingValue(key: string, value: unknown): unknown {
  switch (key) {
    case 'theme':
      return typeof value === 'string' && VALID_THEMES.has(value) ? value : DEFAULTS.theme
    case 'defaultFormat':
      return typeof value === 'string' && VALID_FORMATS.has(value) ? value : DEFAULTS.defaultFormat
    case 'ollamaModel':
      return typeof value === 'string' && value.length <= 128 && /^[\w.:+-]+$/.test(value)
        ? value
        : DEFAULTS.ollamaModel
    case 'editorFontFamily':
      return typeof value === 'string' && VALID_FONTS.has(value) ? value : DEFAULTS.editorFontFamily
    case 'lightAccentColor':
      return value === null || (typeof value === 'string' && HEX_COLOR.test(value))
        ? value as string | null
        : DEFAULTS.lightAccentColor
    case 'darkAccentColor':
      return value === null || (typeof value === 'string' && HEX_COLOR.test(value))
        ? value as string | null
        : DEFAULTS.darkAccentColor
    case 'musicVolume':
      return typeof value === 'number' ? Math.min(100, Math.max(0, value)) : DEFAULTS.musicVolume
    case 'uiScale':
      return typeof value === 'number' ? Math.min(125, Math.max(75, value)) : DEFAULTS.uiScale
    case 'editorFontSize':
      return typeof value === 'number' ? Math.max(8, Math.min(72, value)) : DEFAULTS.editorFontSize
    case 'pomodoroWorkMinutes':
    case 'pomodoroBreakMinutes':
      return typeof value === 'number' ? Math.max(1, Math.min(120, value)) : DEFAULTS[key as keyof AppSettingsOut]
    case 'slidesRightPanelWidth':
      return typeof value === 'number' ? Math.max(240, Math.min(640, value)) : DEFAULTS.slidesRightPanelWidth
    default:
      return value
  }
}

function loadSettings(): AppSettingsOut {
  const db = getSettingsDb()
  const rows = db.prepare('SELECT key, value FROM settings').all() as Array<{ key: string; value: string }>
  const map = new Map(rows.map((r) => [r.key, r.value]))

  const get = <T>(key: string, fallback: T): T => {
    const raw = map.get(key)
    if (raw === undefined) return fallback
    try { return JSON.parse(raw) as T } catch { return fallback }
  }

  return {
    theme: VALID_THEMES.has(get('theme', DEFAULTS.theme)) ? get('theme', DEFAULTS.theme) : DEFAULTS.theme,
    defaultFormat: VALID_FORMATS.has(get('defaultFormat', DEFAULTS.defaultFormat)) ? get('defaultFormat', DEFAULTS.defaultFormat) : DEFAULTS.defaultFormat,
    wordCountExcludesHeader: get('wordCountExcludesHeader', DEFAULTS.wordCountExcludesHeader),
    defaultWordCountGoal: get('defaultWordCountGoal', DEFAULTS.defaultWordCountGoal),
    ollamaModel: get('ollamaModel', DEFAULTS.ollamaModel) || DEFAULTS.ollamaModel,
    pomodoroWorkMinutes: Math.max(1, get('pomodoroWorkMinutes', DEFAULTS.pomodoroWorkMinutes)),
    pomodoroBreakMinutes: Math.max(1, get('pomodoroBreakMinutes', DEFAULTS.pomodoroBreakMinutes)),
    musicVolume: Math.min(100, Math.max(0, get('musicVolume', DEFAULTS.musicVolume))),
    ambientVolumes: get('ambientVolumes', DEFAULTS.ambientVolumes),
    typewriterMode: get('typewriterMode', DEFAULTS.typewriterMode),
    editorFontFamily: get('editorFontFamily', DEFAULTS.editorFontFamily) || DEFAULTS.editorFontFamily,
    editorFontSize: Math.max(8, Math.min(72, get('editorFontSize', DEFAULTS.editorFontSize))),
    headingFontSizes: (() => {
      const v = get('headingFontSizes', DEFAULTS.headingFontSizes)
      const clamp = (n: number) => Math.max(8, Math.min(96, n))
      return { h1: clamp(v.h1 ?? DEFAULTS.headingFontSizes.h1), h2: clamp(v.h2 ?? DEFAULTS.headingFontSizes.h2), h3: clamp(v.h3 ?? DEFAULTS.headingFontSizes.h3) }
    })(),
    lightAccentColor: get('lightAccentColor', DEFAULTS.lightAccentColor),
    darkAccentColor:  get('darkAccentColor',  DEFAULTS.darkAccentColor),
    uiScale: Math.min(125, Math.max(75, get('uiScale', DEFAULTS.uiScale))),
    slidesRightPanelWidth: Math.max(240, Math.min(640, get('slidesRightPanelWidth', DEFAULTS.slidesRightPanelWidth))),
  }
}

export function registerSettingsHandlers(): void {
  const upsert = getSettingsDb().prepare(
    'INSERT INTO settings (key, value) VALUES (?, ?) ON CONFLICT(key) DO UPDATE SET value = excluded.value'
  )

  ipcMain.handle('settings:get', (): AppSettingsOut => loadSettings())

  ipcMain.handle('settings:set', (_, data: unknown): void => {
    if (!data || typeof data !== 'object') throw new Error('Invalid settings payload')
    const d = data as Record<string, unknown>
    for (const [key, value] of Object.entries(d)) {
      if (!APP_SETTING_KEYS.has(key)) continue
      upsert.run(key, JSON.stringify(validateSettingValue(key, value)))
    }
  })
}

