import { useState, useEffect, useRef } from 'react'
import { Search, ChevronUp, ChevronDown, X, Replace } from 'lucide-react'
import type { Editor } from '@tiptap/react'
import { getFindState } from '@/extensions/findExtension'
import { cn } from '@/lib/utils'

interface FindWidgetProps {
  editor: Editor | null
  open: boolean
  onClose: () => void
  onNavigate?: () => void
}

export function FindWidget({ editor, open, onClose, onNavigate }: FindWidgetProps): JSX.Element | null {
  const [query, setQuery] = useState('')
  const [replaceValue, setReplaceValue] = useState('')
  const [showReplace, setShowReplace] = useState(false)
  const [matchInfo, setMatchInfo] = useState({ count: 0, index: 0 })
  const inputRef = useRef<HTMLInputElement>(null)

  // Sync match info from editor on every transaction
  useEffect(() => {
    if (!editor) return
    const update = () => {
      const s = getFindState(editor)
      setMatchInfo({ count: s.results.length, index: s.currentIndex })
    }
    editor.on('transaction', update)
    return () => { editor.off('transaction', update) }
  }, [editor])

  // Focus and clear on open/close
  useEffect(() => {
    if (open) {
      setTimeout(() => inputRef.current?.focus(), 0)
    } else {
      setQuery('')
      setReplaceValue('')
      setShowReplace(false)
      if (editor?.view) editor.commands.clearFind()
    }
  }, [open]) // eslint-disable-line react-hooks/exhaustive-deps

  // Drive findExtension whenever query changes
  useEffect(() => {
    if (!editor) return
    if (query) {
      editor.commands.setFind(query)
    } else {
      editor.commands.clearFind()
    }
  }, [query, editor])

  function handleKeyDown(e: React.KeyboardEvent<HTMLInputElement>) {
    if (e.key === 'Enter') {
      e.preventDefault()
      if (e.shiftKey) {
        editor?.commands.findPrev()
      } else {
        editor?.commands.findNext()
      }
      onNavigate?.()
    }
    if (e.key === 'Escape') {
      onClose()
      editor?.view.focus()
    }
  }

  const matchCount = open ? matchInfo.count : 0
  const matchIndex = matchCount > 0 ? matchInfo.index + 1 : 0

  if (!open) return null

  return (
    <div
      className="pointer-events-auto absolute right-4 top-4 z-50 flex flex-col overflow-hidden rounded-lg border border-border bg-background shadow-lg"
      style={{ minWidth: 280 }}
    >
      {/* Find row */}
      <div className="flex items-center gap-1.5 px-2 py-1.5">
        <button
          className="shrink-0 text-muted-foreground transition-colors hover:text-foreground"
          onClick={() => setShowReplace((s) => !s)}
          title="Toggle replace"
          tabIndex={-1}
        >
          <Replace className={cn('h-3.5 w-3.5 transition-transform', showReplace && 'text-primary')} />
        </button>

        <Search className="h-3 w-3 shrink-0 text-muted-foreground" />

        <input
          ref={inputRef}
          className="min-w-0 flex-1 bg-transparent text-xs outline-none placeholder:text-muted-foreground/50"
          placeholder="Find…"
          value={query}
          onChange={(e) => setQuery(e.target.value)}
          onKeyDown={handleKeyDown}
        />

        {query.length > 0 && (
          <span className="shrink-0 text-[10px] text-muted-foreground tabular-nums">
            {matchCount === 0 ? 'No results' : `${matchIndex} / ${matchCount}`}
          </span>
        )}

        <button
          className="shrink-0 text-muted-foreground transition-colors hover:text-foreground"
          onClick={() => { editor?.commands.findPrev(); onNavigate?.(); inputRef.current?.focus() }}
          title="Previous match (Shift+Enter)"
          tabIndex={-1}
        >
          <ChevronUp className="h-3 w-3" />
        </button>
        <button
          className="shrink-0 text-muted-foreground transition-colors hover:text-foreground"
          onClick={() => { editor?.commands.findNext(); onNavigate?.(); inputRef.current?.focus() }}
          title="Next match (Enter)"
          tabIndex={-1}
        >
          <ChevronDown className="h-3 w-3" />
        </button>
        <button
          className="ml-0.5 shrink-0 text-muted-foreground transition-colors hover:text-foreground"
          onClick={() => { onClose(); editor?.view.focus() }}
          title="Close (Escape)"
          tabIndex={-1}
        >
          <X className="h-3 w-3" />
        </button>
      </div>

      {/* Replace row */}
      {showReplace && (
        <div className="flex items-center gap-1.5 border-t border-border px-2 py-1.5">
          <div className="w-3.5 shrink-0" />
          <input
            className="min-w-0 flex-1 bg-transparent text-xs outline-none placeholder:text-muted-foreground/50"
            placeholder="Replace with…"
            value={replaceValue}
            onChange={(e) => setReplaceValue(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                if (editor && query && replaceValue !== undefined) {
                  editor.commands.findNext()
                  onNavigate?.()
                }
              }
              if (e.key === 'Escape') { onClose(); editor?.view.focus() }
            }}
          />
          <button
            className="shrink-0 rounded px-1.5 py-0.5 text-[10px] text-muted-foreground hover:bg-accent hover:text-foreground"
            title="Replace current match"
            onClick={() => {
              if (!editor || !query) return
              // Replace the current highlighted match by inserting text at selection
              const { from, to } = editor.state.selection
              if (from !== to) {
                editor.chain().focus().deleteRange({ from, to }).insertContentAt(from, replaceValue).run()
              }
              editor.commands.findNext()
              onNavigate?.()
            }}
          >
            Replace
          </button>
        </div>
      )}
    </div>
  )
}

import { useState, useRef, useMemo, useCallback, useEffect } from 'react'
import katex from 'katex'
import {
  Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter,
} from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { Switch } from '@/components/ui/switch'

interface MathModalProps {
  open: boolean
  onClose(): void
  onInsert(latex: string, displayMode: boolean): void
  initialLatex?: string
  initialDisplayMode?: boolean
}

const TEMPLATES: { label: string; latex: string; title: string }[] = [
  { label: 'x=…',        latex: 'x = \\frac{-b \\pm \\sqrt{b^2 - 4ac}}{2a}',   title: 'Quadratic formula' },
  { label: 'a²+b²',      latex: 'a^2 + b^2 = c^2',                              title: 'Pythagorean theorem' },
  { label: 'a/b',        latex: '\\frac{a}{b}',                                  title: 'Fraction' },
  { label: '√x',         latex: '\\sqrt{x}',                                     title: 'Square root' },
  { label: 'dy/dx',      latex: '\\frac{d}{dx}f(x)',                             title: 'Derivative' },
  { label: '∫',          latex: '\\int_a^b f(x)\\,dx',                          title: 'Definite integral' },
  { label: 'Σ',          latex: '\\sum_{i=1}^{n} x_i',                          title: 'Sum notation' },
  { label: 'lim',        latex: '\\lim_{x \\to \\infty} f(x)',                  title: 'Limit' },
  { label: 'α',          latex: '\\alpha',   title: 'Alpha' },
  { label: 'β',          latex: '\\beta',    title: 'Beta' },
  { label: 'γ',          latex: '\\gamma',   title: 'Gamma' },
  { label: 'Δ',          latex: '\\Delta',   title: 'Delta' },
  { label: 'π',          latex: '\\pi',      title: 'Pi' },
  { label: 'θ',          latex: '\\theta',   title: 'Theta' },
  { label: 'σ',          latex: '\\sigma',   title: 'Sigma' },
  { label: '∞',          latex: '\\infty',   title: 'Infinity' },
]

function TextLine({ width, accent = false }: { width: string; accent?: boolean }): JSX.Element {
  return (
    <div
      className={accent ? 'shrink-0 rounded-full bg-primary/50' : 'shrink-0 rounded-full bg-muted-foreground/25'}
      style={{ width, height: '6px' }}
    />
  )
}

export default function MathModal({ open, onClose, onInsert, initialLatex = '', initialDisplayMode = false }: MathModalProps): JSX.Element {
  const [latex, setLatex] = useState(initialLatex)
  const [displayMode, setDisplayMode] = useState(initialDisplayMode)
  const inputRef = useRef<HTMLTextAreaElement>(null)

  // Sync state whenever the modal opens (handles switching between insert/edit mode)
  useEffect(() => {
    if (open) {
      setLatex(initialLatex)
      setDisplayMode(initialDisplayMode)
    }
  }, [open, initialLatex, initialDisplayMode])

  const [previewHtml, previewError] = useMemo<[string, string | null]>(() => {
    const src = latex.trim()
    if (!src) return ['', null]
    try {
      return [katex.renderToString(src, { throwOnError: true, displayMode, output: 'html' }), null]
    } catch (e) {
      return ['', (e as Error).message.replace(/^KaTeX parse error: /, '')]
    }
  }, [latex, displayMode])

  const insertAtCursor = useCallback((template: string) => {
    const el = inputRef.current
    if (!el) {
      setLatex((v) => v + template)
      return
    }
    const start = el.selectionStart ?? latex.length
    const end = el.selectionEnd ?? latex.length
    const next = latex.slice(0, start) + template + latex.slice(end)
    setLatex(next)
    setTimeout(() => {
      el.focus()
      el.setSelectionRange(start + template.length, start + template.length)
    }, 0)
  }, [latex])

  function handleClose() {
    setLatex('')
    setDisplayMode(false)
    onClose()
  }

  function handleInsert() {
    if (!latex.trim() || previewError) return
    onInsert(latex.trim(), displayMode)
    setLatex('')
    setDisplayMode(false)
  }

  const canInsert = latex.trim().length > 0 && !previewError

  return (
    <Dialog open={open} onOpenChange={(o) => { if (!o) handleClose() }}>
      <DialogContent className="flex w-[540px] max-w-[95vw] flex-col gap-0 p-0">
        <DialogHeader className="shrink-0 border-b border-border px-5 py-4">
          <DialogTitle className="text-sm font-semibold">{initialLatex ? 'Edit equation' : 'Insert equation'}</DialogTitle>
        </DialogHeader>

        <div className="flex flex-col gap-4 px-5 py-4">
          {/* Mode toggle */}
          <div className="flex items-center gap-3">
            <span className="text-xs text-muted-foreground">Inline</span>
            <Switch
              checked={displayMode}
              onCheckedChange={setDisplayMode}
              className="scale-90"
            />
            <span className="text-xs text-muted-foreground">Display block</span>
          </div>

          {/* LaTeX input */}
          <div className="flex flex-col gap-1.5">
            <span className="text-xs font-medium">LaTeX</span>
            <textarea
              ref={inputRef}
              className="h-20 w-full resize-none rounded-md border border-input bg-background px-3 py-2 font-mono text-xs outline-none placeholder:text-muted-foreground/50 focus:ring-1 focus:ring-ring"
              placeholder="e.g. x = \frac{-b \pm \sqrt{b^2-4ac}}{2a}"
              value={latex}
              onChange={(e) => setLatex(e.target.value)}
              onKeyDown={(e) => {
                if (e.key === 'Enter' && (e.ctrlKey || e.metaKey)) {
                  e.preventDefault()
                  handleInsert()
                }
              }}
              spellCheck={false}
              autoFocus
            />
          </div>

          {/* Template chips */}
          <div className="flex flex-col gap-1.5">
            <span className="text-xs font-medium text-muted-foreground">Templates</span>
            <div className="flex flex-wrap gap-1">
              {TEMPLATES.map((t) => (
                <button
                  key={t.title}
                  type="button"
                  title={t.title}
                  onClick={() => insertAtCursor(t.latex)}
                  className="rounded border border-border bg-muted/40 px-2 py-0.5 font-mono text-xs transition-colors hover:bg-accent hover:text-accent-foreground"
                >
                  {t.label}
                </button>
              ))}
            </div>
          </div>

          {/* Preview */}
          <div className="flex flex-col gap-1.5">
            <span className="text-xs font-medium text-muted-foreground">Preview</span>
            <div className="rounded-md border border-border bg-editor-page px-4 py-3">
              {previewError ? (
                <span className="text-xs text-destructive">{previewError}</span>
              ) : displayMode ? (
                /* Display block: paragraph above, centred equation, paragraph below */
                <div className="flex flex-col gap-1.5">
                  <TextLine width="100%" />
                  <TextLine width="85%" />
                  <TextLine width="60%" />
                  <div className="flex justify-center py-1.5">
                    {previewHtml
                      ? <span dangerouslySetInnerHTML={{ __html: previewHtml }} />
                      : <TextLine width="40%" accent />}
                  </div>
                  <TextLine width="100%" />
                  <TextLine width="90%" />
                  <TextLine width="45%" />
                </div>
              ) : (
                /* Inline: two full lines, equation sits in the middle of line 2 */
                <div className="flex flex-col gap-1.5">
                  <TextLine width="100%" />
                  <div className="flex items-center gap-1.5">
                    <TextLine width="3rem" />
                    {previewHtml
                      ? <span dangerouslySetInnerHTML={{ __html: previewHtml }} />
                      : <TextLine width="3rem" accent />}
                    <div className="min-w-0 flex-1"><TextLine width="100%" /></div>
                  </div>
                  <TextLine width="55%" />
                </div>
              )}
            </div>
          </div>
        </div>

        <DialogFooter className="shrink-0 border-t border-border px-5 py-3">
          <Button variant="outline" size="sm" className="text-xs" onClick={handleClose}>
            Cancel
          </Button>
          <Button
            size="sm"
            className="text-xs"
            disabled={!canInsert}
            onClick={handleInsert}
            title={canInsert ? `${initialLatex ? 'Update' : 'Insert'} (Ctrl+Enter)` : undefined}
          >
            {initialLatex ? 'Update' : 'Insert'}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  )
}

import { useEffect, useState } from 'react'
import { DocumentTabBar } from '@/components/editor/DocumentTabBar'
import { TitleBarFrame } from '@/components/TitleBarFrame'
import { useAppStore } from '@/store/appStore'
import type { Document } from '@/types'

interface TitleBarProps {
  document: Document | null
  onTitleChange: (title: string) => Promise<void>
}

export default function TitleBar({ document, onTitleChange }: TitleBarProps): JSX.Element {
  const updateDocumentTab = useAppStore((s) => s.updateDocumentTab)

  const [editingTitle, setEditingTitle] = useState(false)
  const [draftTitle, setDraftTitle] = useState('')

  useEffect(() => {
    if (document) {
      updateDocumentTab(document.id, { title: document.title, format: document.format })
    }
  }, [document?.id, document?.title, document?.format, updateDocumentTab])

  async function commitTitleEdit(): Promise<void> {
    setEditingTitle(false)
    if (draftTitle.trim() && draftTitle !== document?.title) {
      await onTitleChange(draftTitle.trim())
      if (document) {
        updateDocumentTab(document.id, { title: draftTitle.trim() })
      }
    }
  }

  return (
    <TitleBarFrame>
      <DocumentTabBar
        activeDocumentId={document?.id}
        editingTitle={editingTitle}
        draftTitle={draftTitle}
        onDraftTitleChange={setDraftTitle}
        onStartTitleEdit={() => { setDraftTitle(document?.title ?? ''); setEditingTitle(true) }}
        onCommitTitleEdit={() => void commitTitleEdit()}
        onCancelTitleEdit={() => setEditingTitle(false)}
      />
    </TitleBarFrame>
  )
}

import { useState, useRef, useEffect, useCallback } from 'react'
import { createPortal } from 'react-dom'
import { motion, AnimatePresence } from 'motion/react'
import { ChromeColorPicker } from '@/components/ui/ChromeColorPicker'
import { useEditorState } from '@tiptap/react'
import type { Editor } from '@tiptap/react'
import { NodeSelection } from '@tiptap/pm/state'
import {
  Bold, Italic, Underline, Strikethrough,
  AlignLeft, AlignCenter, AlignRight, AlignJustify,
  List, ListOrdered, IndentIcon, Outdent,
  Subscript, Superscript, Sigma,
  Image, Link2, Table2, BookOpen, Hash, SeparatorHorizontal,
  ChevronDown, Undo2, Redo2, Highlighter, PaintBucket, BarChart3,
} from 'lucide-react'
import type { DocumentFormat } from '@/types'
import { Button } from '@/components/ui/button'
import { Separator } from '@/components/ui/separator'
import {
  Tooltip, TooltipContent, TooltipTrigger,
} from '@/components/ui/tooltip'
import {
  Popover, PopoverContent, PopoverTrigger,
} from '@/components/ui/popover'
import { ToolbarRightSection } from '@/components/editor/ToolbarRightSection'
import type { PageMargins } from '@/types'

// Plain portal dropdown — bypasses Radix focus/pointer issues in Electron
function ColorPickerDropdown({
  trigger,
  tooltip,
  onOpen,
  children,
}: {
  trigger: React.ReactNode
  tooltip: string
  onOpen?: () => void
  children: (close: () => void) => React.ReactNode
}) {
  const [open, setOpen] = useState(false)
  const [pos, setPos] = useState({ top: 0, left: 0 })
  const btnRef = useRef<HTMLDivElement>(null)
  const pickerRef = useRef<HTMLDivElement>(null)

  const close = useCallback(() => setOpen(false), [])

  useEffect(() => {
    if (!open) return
    function onDown(e: MouseEvent) {
      if (pickerRef.current?.contains(e.target as Node)) return
      if (btnRef.current?.contains(e.target as Node)) return
      setOpen(false)
    }
    function onKey(e: KeyboardEvent) { if (e.key === 'Escape') setOpen(false) }
    document.addEventListener('mousedown', onDown)
    document.addEventListener('keydown', onKey)
    return () => { document.removeEventListener('mousedown', onDown); document.removeEventListener('keydown', onKey) }
  }, [open])

  function handleClick() {
    if (!btnRef.current) return
    const r = btnRef.current.getBoundingClientRect()
    const left = Math.max(4, r.left + r.width / 2 - 110)
    setPos({ top: r.bottom + 4, left })
    const opening = !open
    setOpen((o) => !o)
    if (opening) onOpen?.()
  }

  return (
    <Tooltip>
      <TooltipTrigger asChild>
        <div ref={btnRef} onClick={handleClick} style={{ display: 'inline-flex' }}>
          {trigger}
        </div>
      </TooltipTrigger>
      <TooltipContent side="bottom" className="text-xs">{tooltip}</TooltipContent>
      {createPortal(
        <AnimatePresence>
          {open && (
            <div
              ref={pickerRef}
              style={{ position: 'fixed', top: pos.top, left: pos.left, zIndex: 99999 }}
              onMouseDown={(e) => {
                e.stopPropagation()
                if ((e.target as HTMLElement).tagName !== 'INPUT') e.preventDefault()
              }}
            >
              <motion.div
                initial={{ opacity: 0, scale: 0.95, y: -4 }}
                animate={{ opacity: 1, scale: 1, y: 0 }}
                exit={{ opacity: 0, scale: 0.95, y: -4 }}
                transition={{ duration: 0.18, ease: [0.25, 0.1, 0.25, 1] }}
              >
                {children(close)}
              </motion.div>
            </div>
          )}
        </AnimatePresence>,
        document.body
      )}
    </Tooltip>
  )
}
