// ── Shared menu item ─────────────────────────────────────────────────────────

function MenuItem({
  icon: Icon,
  label,
  shortcut,
  danger,
  onClick,
}: {
  icon: React.ComponentType<{ className?: string }>
  label: string
  shortcut?: string
  danger?: boolean
  onClick: () => void
