import { useDocument } from '@/hooks/useDocument'
import type { SheetContent, ChartDef, ChartType } from '@/types/sheet'
import { isSheetContent, createInitialSheetContent } from '@/types/sheet'
import { createSheetActionHandler } from './sheetAiActions'
import { SheetInsightsTab } from './SheetInsightsTab'
import type { CellRef } from '@/lib/ai/proseActions'
import { Lightbulb } from 'lucide-react'
import { FileEditorTitleBar } from '@/components/editor/FileEditorTitleBar'
import { SheetToolbar, type ToolbarState } from './SheetToolbar'
import { SheetTabBar } from './SheetTabBar'
import { sheetTabToFSSheet, fsDataToSheetContent, colToLetter, cellAddress, htToAlign } from './sheetUtils'
import { AUTO_SAVE_DEBOUNCE_MS, AI_PANEL_WIDTH } from '@/constants'
import { useAppStore } from '@/store/appStore'
import AiPanel from '@/components/editor/AiPanel'
import { TooltipProvider } from '@/components/ui/tooltip'
import { cn } from '@/lib/utils'
import { useMusicContext } from '@/contexts/MusicContext'
import { AMBIENT_LAYERS } from '@/hooks/useMusic'
import { useIsActiveTab } from '@/hooks/useIsActiveTab'
import SettingsModal from '@/components/settings/SettingsModal'
import { SheetExportModal } from './SheetExportModal'
import { ChartDialog } from './ChartDialog'
import { ChartOverlay } from './ChartOverlay'
import { dispatchUndoRedoKey } from '@/lib/simulateUndoRedo'
import { useContextMenuIcons } from '@/hooks/useContextMenuIcons'
import { runThumbnailGenerationOnce, clampRectToViewport } from '@/lib/thumbnailGeneration'

// ── Helpers ───────────────────────────────────────────────────────────────────

// FortuneSheet's native right-click menu has no per-item class/data-attribute
// to target — only the rendered (English) label text identifies each action.
// Unmapped labels (e.g. "Insert N rows/columns", which embed a live input and
// vary their text) are simply left without an icon.
const FORTUNE_CONTEXT_MENU_ICONS: Record<string, React.ComponentType<{ className?: string }>> = {
  Copy,
  Paste: Clipboard,
  'Delete selected Row': Trash2,
  'Delete selected Column': Trash2,
  'Hide selected Row': EyeOff,
  'Hide selected Column': EyeOff,
  'Show hidden Row': Eye,
  'Show hidden Column': Eye,
  'Clear content': Eraser,
  'Ascending sort': ArrowUpAZ,
  'Descending sort': ArrowDownAZ,
  Filter,
  'Insert image': ImageIcon,
  'Insert link': Link2,
}

function parseSheetContent(raw: unknown): SheetContent {
  if (isSheetContent(raw)) return raw
  return createInitialSheetContent()
}

const DEFAULT_TOOLBAR: ToolbarState = {
  bold: false, italic: false, underline: false,
  align: null, wrap: false, fontFamily: 'Calibri',
  fontSize: 11, textColor: '#000000', bgColor: '#ffffff',
  isMerged: false,
}

// ── AI context builder ────────────────────────────────────────────────────────

function buildSheetContext(sheet: Sheet, tabName: string, selectedRow: number, selectedCol: number): string {
  const data = sheet.data
  if (!data) return `Sheet tab: "${tabName}"\n(no data)`

  const rows = Math.min(data.length, 21)
  const firstRow = data[0]
  const cols = firstRow ? Math.min(firstRow.length, 26) : 26

  const headers: string[] = []
  for (let c = 0; c < cols; c++) {
    const cell = data[0]?.[c]
    const v = cell?.m ?? cell?.v
    headers.push(v !== undefined && v !== null && String(v).trim() !== '' ? String(v) : colToLetter(c))
  }

  const sep = headers.map(() => '---').join(' | ')
  const headerRow = headers.join(' | ')
  const dataRows: string[] = []
  for (let r = 1; r < rows; r++) {
    const cells: string[] = []
    for (let c = 0; c < cols; c++) {
      const cell = data[r]?.[c]
      const v = cell?.m ?? cell?.v
      cells.push(v !== undefined && v !== null ? String(v) : '')
    }
    if (cells.every((c) => c === '')) continue
    dataRows.push(cells.join(' | '))
  }

  const formulaCells: string[] = []
  outer: for (let r = 0; r < data.length; r++) {
    const row = data[r]
    if (!row) continue
    for (let c = 0; c < row.length; c++) {
      const cell = row[c]
      if (cell?.f) {
        formulaCells.push(`${cellAddress(r, c)}: ${cell.f} → ${cell.m ?? cell.v ?? ''}`)
        if (formulaCells.length >= 50) break outer
      }
    }
  }

  const parts = [
    `Sheet tab: "${tabName}"`,
    '',
    `Data (${dataRows.length} rows, ${cols} columns):`,
    `| ${headerRow} |`,
    `| ${sep} |`,
    ...dataRows.map((row) => `| ${row} |`),
  ]

  if (formulaCells.length > 0) {
    parts.push('', 'Formula cells:', ...formulaCells)
  }

  parts.push('', `Selected cell: ${cellAddress(selectedRow, selectedCol)}`)
  const sel = data[selectedRow]?.[selectedCol]
  if (sel) {
    const src = sel.f ?? sel.v
    if (src !== undefined && src !== null) {
      parts.push(`  Value: ${src}`)
      if (sel.f) parts.push(`  Computed: ${sel.m ?? sel.v ?? ''}`)
    }
  }

  return parts.join('\n')
}

// ── Component ─────────────────────────────────────────────────────────────────

interface TabInfo {
  id: string
  name: string
}

interface SheetsEditorProps {
  documentId: string
}

export function SheetsEditor({ documentId }: SheetsEditorProps) {
  useContextMenuIcons('.fortune-menuitem-row, .luckysheet-cols-menuitem-content', FORTUNE_CONTEXT_MENU_ICONS)
  const isActive = useIsActiveTab(documentId)
  const { document: doc, saveStatus, notifySaveStatus } = useDocument(documentId)
  const workbookRef = useRef<WorkbookInstance | null>(null)
  const workbookWrapperRef = useRef<HTMLDivElement>(null)
  const [settingsOpen, setSettingsOpen] = useState(false)
  const [exportOpen, setExportOpen] = useState(false)
  const [chartDialogOpen, setChartDialogOpen] = useState(false)
  const [editingChart, setEditingChart] = useState<ChartDef | undefined>(undefined)
  const [charts, setCharts] = useState<ChartDef[]>([])
  const chartsRef = useRef<ChartDef[]>([])
  // Charts are positioned in unscrolled grid-content coordinates, so the
  // overlay needs the live scroll offset to track the grid instead of
  // floating fixed over it. FortuneSheet's grid scrolling isn't exposed via
  // its public API — but it does drive two real (invisible) native scroll
  // elements internally, .luckysheet-scrollbar-x/-y, so we read scroll
  // position directly from those.
  const [gridScroll, setGridScroll] = useState({ x: 0, y: 0 })
  const aiPanelOpen = useAppStore((s) => s.aiPanelOpen)
  const theme = useAppStore((s) => s.theme)
  const setPendingAiPrompt = useAppStore((s) => s.setPendingAiPrompt)
  const setAiPanelOpen = useAppStore((s) => s.setAiPanelOpen)

  // AI panel width — resizable via drag handle, same behavior as Documents'
  // AI panel (Editor.tsx), persisted to the same localStorage key so the
  // width preference is shared across file types.
  const [aiPanelWidth, setAiPanelWidth] = useState(() => {
    const v = localStorage.getItem('prose-ai-panel-width')
    return v ? Math.max(240, parseInt(v)) : AI_PANEL_WIDTH
  })
  const aiPanelDragRef = useRef<{ x: number; width: number } | null>(null)
  const aiPanelWidthRef = useRef(aiPanelWidth)
  useEffect(() => { aiPanelWidthRef.current = aiPanelWidth }, [aiPanelWidth])
  // Suppresses the panel's open/close width transition while actively
  // drag-resizing — else every mousemove retargets an eased animation and the
  // panel edge lags behind the cursor instead of tracking it 1:1.
  const [isResizingAiPanel, setIsResizingAiPanel] = useState(false)

  useEffect(() => {
    function onMouseMove(e: MouseEvent): void {
      if (!aiPanelDragRef.current) return
      const delta = aiPanelDragRef.current.x - e.clientX
      const width = Math.min(600, Math.max(240, aiPanelDragRef.current.width + delta))
      setAiPanelWidth(width)
      aiPanelWidthRef.current = width
    }
    function onMouseUp(): void {
      if (!aiPanelDragRef.current) return
      aiPanelDragRef.current = null
      setIsResizingAiPanel(false)
      localStorage.setItem('prose-ai-panel-width', String(aiPanelWidthRef.current))
      if (globalThis.document?.body) {
        globalThis.document.body.style.cursor = ''
        globalThis.document.body.style.userSelect = ''
      }
    }
    window.addEventListener('mousemove', onMouseMove)
    window.addEventListener('mouseup', onMouseUp)
    return () => {
      window.removeEventListener('mousemove', onMouseMove)
      window.removeEventListener('mouseup', onMouseUp)
    }
  }, [])

  // Music
  const music = useMusicContext()
  const activeAmbient = AMBIENT_LAYERS.filter((l) => music?.ambientEnabled[l.id])
  const ambientPlaying =
    activeAmbient.length === 0 ? null
    : activeAmbient.length === 1 ? activeAmbient[0]!.label
    : activeAmbient.length === 2 ? `${activeAmbient[0]!.label} + ${activeAmbient[1]!.label}`
    : `${activeAmbient.length} Sounds`

  // Initial FortuneSheet data — computed once when doc loads, then stable
  const fsDataRef = useRef<Sheet[] | null>(null)
  const [ready, setReady] = useState(false)

  // Tab bar state (lightweight)
  const [tabs, setTabs] = useState<TabInfo[]>([])
  const [activeTabId, setActiveTabId] = useState('')
  const tabsRef = useRef<TabInfo[]>([])
  const activeTabIdRef = useRef('')

  // Zoom state (percentage, 10–400)
  const [zoom, setZoom] = useState(100)

  // Toolbar + formula bar state
  const [toolbarState, setToolbarState] = useState<ToolbarState>(DEFAULT_TOOLBAR)
  const [formulaAddress, setFormulaAddress] = useState('A1')
  const [formulaBarValue, setFormulaBarValue] = useState('')
  const selectedCellRef = useRef({ row: 0, col: 0 })

  // Auto-save
  const saveTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  const pendingDataRef = useRef<Sheet[] | null>(null)
  const zoomChangeRef = useRef(false)

  // Undo/redo enabled state — FortuneSheet keeps its undo stack entirely
  // internal (no public API to query it), so we mirror its depth ourselves:
  // genuine edits push, our own Undo/Redo button clicks pop/push between the
  // two stacks the same way FortuneSheet's internal handleUndo/handleRedo do.
  const undoDepthRef = useRef(0)
  const redoDepthRef = useRef(0)
  const pendingUndoRedoRef = useRef<'undo' | 'redo' | null>(null)
  const undoCountTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  // Safety net for `pendingUndoRedoRef`: if FortuneSheet's real internal stack
  // didn't actually have anything to undo/redo (our mirrored depth had
  // drifted), no onChange follows to clear the flag — left unhandled, it would
  // stay stuck and silently misclassify the NEXT genuine edit as this undo/redo.
  const pendingClearTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  // FortuneSheet fires onChange once while it finishes initializing the sheet
  // it was just given — not a real user edit — which was being miscounted as
  // the first "undo-able" edit, leaving Undo enabled (but non-functional)
  // immediately after opening a sheet. Skip depth tracking for onChange calls
  // that land within this grace window after (re)loading a document.
  const loadedAtRef = useRef(0)
  const INIT_GRACE_MS = 600
  const [canUndo, setCanUndo] = useState(false)
  const [canRedo, setCanRedo] = useState(false)

  const flushAndSave = useCallback(async () => {
    if (saveTimerRef.current) {
      clearTimeout(saveTimerRef.current)
      saveTimerRef.current = null
    }
    const data = pendingDataRef.current
    if (!data) return
    const content = fsDataToSheetContent(data)
    content.charts = chartsRef.current
    notifySaveStatus('saving')
    try {
      await window.prose.documents.update(documentId, { content: JSON.stringify(content) })
      notifySaveStatus('saved')
    } catch (err) {
      console.error('[SheetsEditor] save error:', err)
      notifySaveStatus('error')
    }
  }, [documentId, notifySaveStatus])

  const scheduleSave = useCallback(() => {
    if (saveTimerRef.current) clearTimeout(saveTimerRef.current)
    saveTimerRef.current = setTimeout(() => void flushAndSave(), AUTO_SAVE_DEBOUNCE_MS)
  }, [flushAndSave])

  const setSaveActiveDocument = useAppStore((s) => s.setSaveActiveDocument)

  useEffect(() => {
    if (!isActive) return
    setSaveActiveDocument(async () => { await flushAndSave() })
    return () => setSaveActiveDocument(null)
  }, [isActive, flushAndSave, setSaveActiveDocument])

  // Set zoom via applyOp which uses Immer's applyPatches directly — no frozen-object mutation
  const handleZoomChange = useCallback((newPct: number) => {
    const clamped = Math.min(400, Math.max(10, Math.round(newPct / 10) * 10))
    const wb = workbookRef.current
    if (!wb) return
    const sheets = wb.getAllSheets()
    const activeSheet = sheets.find(s => s.status === 1) ?? sheets[0]
    if (!activeSheet?.id) return
    const ratio = parseFloat((clamped / 100).toFixed(1))
    zoomChangeRef.current = true
    wb.applyOp([
      { op: 'replace', id: String(activeSheet.id), path: ['zoomRatio'], value: ratio },
      { op: 'replace', path: ['zoomRatio'], value: ratio },
    ])
    setZoom(clamped)
  }, [])

  useEffect(() => () => {
    if (saveTimerRef.current) void flushAndSave()
  }, [flushAndSave])

  // Thumbnail generation — fired by the main process after every successful
  // content auto-save. Crops to roughly the first 12 rows / 8 columns instead
  // of the full grid container, using the same column/row sizes configured on
  // the <Workbook> below (defaultColWidth/defaultRowHeight) plus FortuneSheet's
  // standard row/column header sizes, then hands the region off to the main
  // process for the actual 560x315 resize.
  useEffect(() => {
    return window.prose.thumbnails.onGenerate((fileId) => {
      if (fileId !== documentId) return
      void runThumbnailGenerationOnce(fileId, async () => {
        if (!ready) return
        const wrapper = workbookWrapperRef.current
        if (!wrapper) return
        const gridRect = wrapper.getBoundingClientRect()
        if (gridRect.width <= 0 || gridRect.height <= 0) return

        const ROW_HEADER_WIDTH = 46
        const COL_HEADER_HEIGHT = 20
        const COL_WIDTH = 100
        const ROW_HEIGHT = 20
        const cropWidth = Math.min(gridRect.width, ROW_HEADER_WIDTH + 8 * COL_WIDTH)
        const cropHeight = Math.min(gridRect.height, COL_HEADER_HEIGHT + 12 * ROW_HEIGHT)

        const rect = clampRectToViewport({ x: gridRect.left, y: gridRect.top, width: cropWidth, height: cropHeight })
        if (!rect) return
        const base64 = await window.prose.thumbnails.captureRegion(rect)
        await window.prose.thumbnails.save(fileId, base64)
      })
    })
  }, [documentId, ready])

  // Track the grid's scroll offset so the chart overlay can follow it — see
  // the comment on gridScroll's declaration for why we read these elements
  // directly instead of going through FortuneSheet's API.
  useEffect(() => {
    if (!ready) return
    const wrapper = workbookWrapperRef.current
    if (!wrapper) return

    const scrollerX = wrapper.querySelector('.luckysheet-scrollbar-x')
    const scrollerY = wrapper.querySelector('.luckysheet-scrollbar-y')
    if (!scrollerX || !scrollerY) return

    const onScrollX = (): void => setGridScroll((s) => ({ ...s, x: scrollerX.scrollLeft }))
    const onScrollY = (): void => setGridScroll((s) => ({ ...s, y: scrollerY.scrollTop }))
    scrollerX.addEventListener('scroll', onScrollX)
    scrollerY.addEventListener('scroll', onScrollY)
    return () => {
      scrollerX.removeEventListener('scroll', onScrollX)
      scrollerY.removeEventListener('scroll', onScrollY)
    }
  }, [ready])

  // Ctrl+S manual save + Ctrl+0 reset zoom
  useEffect(() => {
    if (!isActive) return
    const onKey = (e: KeyboardEvent) => {
      if (e.ctrlKey && e.key === 's') {
        e.preventDefault()
        if (saveTimerRef.current) clearTimeout(saveTimerRef.current)
        void flushAndSave()
      }
      if (e.ctrlKey && e.key === '0') {
        e.preventDefault()
        handleZoomChange(100)
      }
    }
    window.addEventListener('keydown', onKey)
    return () => window.removeEventListener('keydown', onKey)
  }, [isActive, flushAndSave, handleZoomChange])

  // Load doc and compute initial FS data
  useEffect(() => {
    if (!doc) return
    let content: SheetContent
    try {
      const raw = typeof doc.content === 'string' ? JSON.parse(doc.content) : doc.content
      content = parseSheetContent(raw)
    } catch {
      content = createInitialSheetContent()
    }

    fsDataRef.current = content.tabs.map((tab, i) =>
      sheetTabToFSSheet(tab, tab.id === content.activeTabId, i)
    )
    // Seed the autosave baseline immediately — pendingDataRef otherwise stays
    // null until FortuneSheet's onChange fires, so a chart inserted before any
    // cell edit would never trigger a save (flushAndSave bails on null data).
    // fsDataToSheetContent already handles the celldata-only shape this carries.
    pendingDataRef.current = fsDataRef.current

    const initialTabs = content.tabs.map((t) => ({ id: t.id, name: t.name }))
    tabsRef.current = initialTabs
    setTabs(initialTabs)
    activeTabIdRef.current = content.activeTabId
    setActiveTabId(content.activeTabId)

    const loadedCharts = content.charts ?? []
    chartsRef.current = loadedCharts
    setCharts(loadedCharts)

    // Fresh Workbook instance (key={documentId} below) means FortuneSheet's own
    // undo/redo stack also starts empty — reset our mirrored depth tracking too.
    undoDepthRef.current = 0
    redoDepthRef.current = 0
    pendingUndoRedoRef.current = null
    if (undoCountTimerRef.current) { clearTimeout(undoCountTimerRef.current); undoCountTimerRef.current = null }
    if (pendingClearTimerRef.current) { clearTimeout(pendingClearTimerRef.current); pendingClearTimerRef.current = null }
    loadedAtRef.current = Date.now()
    setCanUndo(false)
    setCanRedo(false)

    setReady(true)
  // Only re-initialize when the document ID changes (opening a different file)
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [doc?.id])

  // FortuneSheet only re-measures its grid on a window resize event — it
  // doesn't observe its own container resizing — so it needs a nudge: once at
  // mount (container settling into its initial layout) and again whenever the
  // AI panel's width actually changes (drag-resize or open/close), once that
  // change has visually settled (150ms covers both a debounced drag and the
  // panel's own 0.12s open/close animation).
  useEffect(() => {
    if (!ready) return
    const id = requestAnimationFrame(() => window.dispatchEvent(new Event('resize')))
    return () => cancelAnimationFrame(id)
  }, [ready])

  useEffect(() => {
    if (!ready) return
    const id = setTimeout(() => window.dispatchEvent(new Event('resize')), 150)
    return () => clearTimeout(id)
  }, [ready, aiPanelWidth, aiPanelOpen])

  // Context menu AI events
  useEffect(() => {
    if (!isActive) return
    const onExplain = (e: Event) => {
      const { formula } = (e as CustomEvent<{ formula: string }>).detail
      setAiPanelOpen(true)
      setPendingAiPrompt(`Explain this formula: ${formula}`)
    }
    const onGenerate = () => {
      setAiPanelOpen(true)
      setPendingAiPrompt('Generate a formula for this column. Describe what you want to calculate:')
    }
    window.addEventListener('prose-sheet-explain-formula', onExplain)
    window.addEventListener('prose-sheet-generate-formula', onGenerate)
    return () => {
      window.removeEventListener('prose-sheet-explain-formula', onExplain)
      window.removeEventListener('prose-sheet-generate-formula', onGenerate)
    }
  }, [isActive, setAiPanelOpen, setPendingAiPrompt])

  // AI context getter
  const getSheetContext = useCallback((): string => {
    const wb = workbookRef.current
    if (!wb) return ''
    try {
      const sheets = wb.getAllSheets()
      const active = sheets.find((s) => s.status === 1) ?? sheets[0]
      if (!active) return ''
      const tabName = tabsRef.current.find((t) => t.id === String(active.id))?.name ?? active.name
      const { row, col } = selectedCellRef.current
      return buildSheetContext(active, tabName, row, col)
    } catch {
      return ''
    }
  }, [])

  const onInsertFormula = useCallback((formula: string) => {
    const wb = workbookRef.current; if (!wb) return
    const { row, col } = selectedCellRef.current
    wb.setCellValue(row, col, formula)
  }, [])

  // Writes an AI-generated table (parsed from a markdown response) starting
  // at the selected cell — the first row is treated as a header row.
  const onInsertTableData = useCallback((rows: string[][]) => {
    const wb = workbookRef.current; if (!wb) return
    const { row: startRow, col: startCol } = selectedCellRef.current
    rows.forEach((rowValues, r) => {
      rowValues.forEach((value, c) => {
        wb.setCellValue(startRow + r, startCol + c, value)
      })
    })
  }, [])

  // commitFormulaBar — writes formula bar value back to selected cell
  const commitFormulaBar = useCallback(() => {
    const wb = workbookRef.current; if (!wb) return
    const { row, col } = selectedCellRef.current
    wb.setCellValue(row, col, formulaBarValue)
  }, [formulaBarValue])

  // Tab operations
  const switchTab = useCallback((tabId: string) => {
    const wb = workbookRef.current; if (!wb) return
    wb.activateSheet({ id: tabId })
    // FortuneSheet's onChange doesn't reliably fire on a pure activation (no data
    // mutation), so update the tab bar's active state immediately rather than
    // waiting for handleChange to notice the new status:1 sheet.
    activeTabIdRef.current = tabId
    setActiveTabId(tabId)
  }, [])

  // Marks the next onChange as consuming this undo/redo (see handleChange)
  // rather than being a genuine edit. Armed with a short safety timeout: if
  // our mirrored depth was wrong and FortuneSheet's real stack had nothing to
  // do, no onChange follows to clear the flag, so clear it ourselves instead
  // of leaving it stuck to misclassify the next real edit.
  const armPendingUndoRedo = useCallback((action: 'undo' | 'redo') => {
    if (undoCountTimerRef.current) { clearTimeout(undoCountTimerRef.current); undoCountTimerRef.current = null }
    if (pendingClearTimerRef.current) clearTimeout(pendingClearTimerRef.current)
    pendingUndoRedoRef.current = action
    pendingClearTimerRef.current = setTimeout(() => {
      pendingUndoRedoRef.current = null
      pendingClearTimerRef.current = null
    }, 250)
  }, [])

  // FortuneSheet has no public undo()/redo() API — it only responds to a real
  // keydown on its hidden cell-editor element, so locate that within this
  // sheet's own wrapper and dispatch there.
  const handleUndo = useCallback(() => {
    if (undoDepthRef.current === 0) return
    armPendingUndoRedo('undo')
    const target = workbookWrapperRef.current?.querySelector('.luckysheet-cell-input')
    dispatchUndoRedoKey(target, 'undo')
  }, [armPendingUndoRedo])

  const handleRedo = useCallback(() => {
    if (redoDepthRef.current === 0) return
    armPendingUndoRedo('redo')
    const target = workbookWrapperRef.current?.querySelector('.luckysheet-cell-input')
    dispatchUndoRedoKey(target, 'redo')
  }, [armPendingUndoRedo])

  // A native Ctrl+Z/Ctrl+Y keypress goes straight to FortuneSheet's own
  // keydown handler on its hidden cell-input, bypassing handleUndo/handleRedo
  // (and armPendingUndoRedo) entirely — so it used to always fall into
  // handleChange's "genuine edit" branch, corrupting the mirrored depth
  // counters relative to FortuneSheet's real stack. Intercept in the CAPTURE
  // phase (fires before FortuneSheet's bubble-phase handler) so native hotkeys
  // go through the exact same bookkeeping as the toolbar buttons.
  useEffect(() => {
    if (!ready || !isActive) return
    const wrapper = workbookWrapperRef.current
    if (!wrapper) return
    function onKeyCapture(e: KeyboardEvent): void {
      if (!e.ctrlKey || (e.code !== 'KeyZ' && e.code !== 'KeyY')) return
      const isRedo = e.code === 'KeyY' || e.shiftKey
      const depthRef = isRedo ? redoDepthRef : undoDepthRef
      if (depthRef.current === 0) return
      armPendingUndoRedo(isRedo ? 'redo' : 'undo')
    }
    wrapper.addEventListener('keydown', onKeyCapture, true)
    return () => wrapper.removeEventListener('keydown', onKeyCapture, true)
  }, [ready, isActive, armPendingUndoRedo])

  const addTab = useCallback(() => {
    const wb = workbookRef.current; if (!wb) return
    wb.addSheet()
    // addSheet() activates the new sheet internally (changeSheet sets
    // ctx.currentSheetId synchronously) but doesn't reliably trigger onChange —
    // same gap as switchTab, so read the now-active sheet back directly.
    const sheets = wb.getAllSheets()
    const active = sheets.find(s => s.status === 1) ?? sheets[sheets.length - 1]
    const newId = active?.id !== undefined ? String(active.id) : ''
    if (newId) {
      activeTabIdRef.current = newId
      setActiveTabId(newId)
    }
  }, [])

  const renameTab = useCallback((tabId: string, name: string) => {
    const wb = workbookRef.current; if (!wb) return
    wb.setSheetName(name, { id: tabId })
  }, [])

  const deleteTab = useCallback((tabId: string) => {
    if (tabsRef.current.length <= 1) return
    const wb = workbookRef.current; if (!wb) return
    wb.deleteSheet({ id: tabId })
  }, [])

  // ── Chart management ──────────────────────────────────────────────────────

  const updateChartsAndSave = useCallback((updated: ChartDef[]) => {
    chartsRef.current = updated
    setCharts(updated)
    scheduleSave()
  }, [scheduleSave])

  const handleInsertChart = useCallback((partial: Omit<ChartDef, 'id' | 'x' | 'y' | 'width' | 'height'>) => {
    const offset = chartsRef.current.filter(c => c.sheetId === partial.sheetId).length * 20
    const newChart: ChartDef = {
      ...partial,
      id: `chart-${Date.now()}`,
      x: 20 + offset,
      y: 20 + offset,
      width: 520,
      height: 340,
    }
    updateChartsAndSave([...chartsRef.current, newChart])
  }, [updateChartsAndSave])

  const handleUpdateChart = useCallback((updated: ChartDef) => {
    updateChartsAndSave(chartsRef.current.map(c => c.id === updated.id ? updated : c))
  }, [updateChartsAndSave])

  const handleDeleteChart = useCallback((id: string) => {
    updateChartsAndSave(chartsRef.current.filter(c => c.id !== id))
  }, [updateChartsAndSave])

  const handleEditChart = useCallback((chart: ChartDef) => {
    setEditingChart(chart)
    setChartDialogOpen(true)
  }, [])

  const handleOpenInsertChart = useCallback(() => {
    setEditingChart(undefined)
    setChartDialogOpen(true)
  }, [])

  // Get the initial range from current selection for the chart dialog
  const getInitialChartRange = useCallback((): string => {
    try {
      const coords = workbookRef.current?.getSelectionCoordinates()
      return coords?.[0] ?? ''
    } catch {
      return ''
    }
  }, [])

  // ── End chart management ──────────────────────────────────────────────────

  // ── AI actions + insights ──────────────────────────────────────────────────

  const aiActionHandler = useMemo(() => createSheetActionHandler({
    workbookRef,
    getActiveSheetId: () => activeTabIdRef.current,
    insertChart: handleInsertChart,
    onMutated: scheduleSave,
  }), [handleInsertChart, scheduleSave])

  const insightsInsertFormula = useCallback((cell: CellRef, formula: string) => {
    const wb = workbookRef.current; if (!wb) return
    wb.setCellValue(cell.row, cell.col, formula)
    scheduleSave()
  }, [scheduleSave])

  const insightsInsertChart = useCallback((chart: { type: ChartType; dataRange: string; title: string }) => {
    handleInsertChart({
      sheetId: activeTabIdRef.current,
      type: chart.type,
      dataRange: chart.dataRange,
      title: chart.title,
    })
  }, [handleInsertChart])

  // ── End AI actions + insights ──────────────────────────────────────────────

  // onChange: sync tab bar, zoom, and schedule save
  const handleChange = useCallback((data: Sheet[]) => {
    pendingDataRef.current = data

    const newTabs = data.map((s) => ({ id: String(s.id ?? ''), name: s.name }))
    const prevTabs = tabsRef.current
    const tabsChanged = newTabs.length !== prevTabs.length ||
      newTabs.some((t, i) => t.id !== prevTabs[i]?.id || t.name !== prevTabs[i]?.name)
    if (tabsChanged) {
      tabsRef.current = newTabs
      setTabs(newTabs)
    }

    const active = data.find((s) => s.status === 1) ?? data[0]
    const newActiveId = String(active?.id ?? '')
    if (newActiveId !== activeTabIdRef.current) {
      activeTabIdRef.current = newActiveId
      setActiveTabId(newActiveId)
    }

    // Sync zoom from active sheet
    const newZoom = Math.round((active?.zoomRatio ?? 1) * 100)
    setZoom(newZoom)

    if (zoomChangeRef.current) {
      zoomChangeRef.current = false
      return
    }

    scheduleSave()

    // Undo/redo depth tracking — see comment near the refs' declaration.
    if (pendingUndoRedoRef.current === 'undo') {
      if (pendingClearTimerRef.current) { clearTimeout(pendingClearTimerRef.current); pendingClearTimerRef.current = null }
      undoDepthRef.current = Math.max(0, undoDepthRef.current - 1)
      redoDepthRef.current += 1
      pendingUndoRedoRef.current = null
      setCanUndo(undoDepthRef.current > 0)
      setCanRedo(true)
    } else if (pendingUndoRedoRef.current === 'redo') {
      if (pendingClearTimerRef.current) { clearTimeout(pendingClearTimerRef.current); pendingClearTimerRef.current = null }
      redoDepthRef.current = Math.max(0, redoDepthRef.current - 1)
      undoDepthRef.current += 1
      pendingUndoRedoRef.current = null
      setCanUndo(true)
      setCanRedo(redoDepthRef.current > 0)
    } else if (Date.now() - loadedAtRef.current < INIT_GRACE_MS) {
      // FortuneSheet settling in after (re)loading a document — not a real edit.
    } else {
      // A genuine edit. Debounce briefly so a continuous drag (range fill,
      // multi-cell paste) collapses into one counted undo step instead of one
      // per onChange firing, without delaying the button's enabled state by
      // the (much longer) save debounce.
      if (undoCountTimerRef.current) clearTimeout(undoCountTimerRef.current)
      undoCountTimerRef.current = setTimeout(() => {
        undoDepthRef.current += 1
        redoDepthRef.current = 0
        setCanUndo(true)
        setCanRedo(false)
      }, 300)
    }
  }, [scheduleSave])

  // Stable hooks object — closures use refs so hooks object never changes
  const fortuneHooks = useMemo<Hooks>(() => ({
    afterSelectionChange: (_sheetId: string, selection: Selection) => {
      const wb = workbookRef.current; if (!wb) return
      const r = selection.row_focus ?? selection.row[0] ?? 0
      const c = selection.column_focus ?? selection.column[0] ?? 0
      selectedCellRef.current = { row: r, col: c }

      // Formula bar
      try {
        const rawFormula = wb.getCellValue(r, c, { type: 'f' }) as string | undefined
        const formula = rawFormula ? rawFormula.replace(/<[^>]*>/g, '') : undefined
        const value = wb.getCellValue(r, c, { type: 'v' })
        setFormulaAddress(cellAddress(r, c))
        setFormulaBarValue(formula ?? (value != null ? String(value) : ''))
      } catch { /* ignore if workbook not ready */ }

      // Toolbar state — read from live sheet data
      try {
        const sheets = wb.getAllSheets()
        const active = sheets.find((s) => s.status === 1) ?? sheets[0]
        const cell = active?.data?.[r]?.[c] ?? null

        setToolbarState({
          bold: cell?.bl === 1,
          italic: cell?.it === 1,
          underline: cell?.un === 1,
          fontFamily: typeof cell?.ff === 'string' ? cell.ff : 'Calibri',
          fontSize: typeof cell?.fs === 'number' ? cell.fs : 11,
          textColor: cell?.fc ?? '#000000',
          bgColor: cell?.bg ?? '#ffffff',
          align: htToAlign(cell?.ht),
          wrap: cell?.tb === '2',
          isMerged: !!cell?.mc && cell.mc.rs !== undefined,
        })
      } catch { /* ignore */ }
    },
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }), [])

  if (!ready || !fsDataRef.current) {
    return (
      <TooltipProvider delayDuration={400}>
        <div className="flex h-screen flex-col bg-background">
          <FileEditorTitleBar />
        </div>
      </TooltipProvider>
    )
  }

  return (
    <TooltipProvider delayDuration={400}>
      <div className="flex h-screen flex-col bg-background">
        <FileEditorTitleBar />
        <SheetToolbar
          workbookRef={workbookRef}
          state={toolbarState}
          cellAddress={formulaAddress}
          formulaBarValue={formulaBarValue}
          onFormulaBarChange={setFormulaBarValue}
          onFormulaBarCommit={commitFormulaBar}
          onFormatChange={scheduleSave}
          documentId={documentId}
          onSettingsOpen={() => setSettingsOpen(true)}
          onSheetExport={() => setExportOpen(true)}
          onInsertChart={handleOpenInsertChart}
          onUndo={handleUndo}
          onRedo={handleRedo}
          canUndo={canUndo}
          canRedo={canRedo}
        />

        {/* Grid + AI panel row. The grid shrinks to fill whatever space the
            AI panel leaves — FortuneSheet doesn't observe its own container
            resizing, so a window-resize event is dispatched below on every
            width change (drag, open/close) to force it to re-measure. */}
        <div className="flex min-h-0 flex-1">
          {/* FortuneSheet container */}
          <div
            ref={workbookWrapperRef}
            className={cn(
              'relative flex h-full min-h-0 min-w-0 flex-1 flex-col overflow-hidden',
              theme === 'dark' && 'fortune-dark'
            )}
          >
            <ChartOverlay
              charts={charts}
              activeSheetId={activeTabId}
              workbookRef={workbookRef}
              onUpdateChart={handleUpdateChart}
              onDeleteChart={handleDeleteChart}
              onEditChart={handleEditChart}
              scrollX={gridScroll.x}
              scrollY={gridScroll.y}
            />
            <Workbook
              key={documentId}
              ref={workbookRef}
              data={fsDataRef.current}
              onChange={handleChange}
              showToolbar={false}
              showFormulaBar={false}
              showSheetTabs={false}
              lang="en"
              hooks={fortuneHooks}
              defaultColWidth={100}
              defaultRowHeight={20}
            />
          </div>

          {/* AI panel — resizable, same width-animated open/close as Slides'
              right panel (SlidesEditor.tsx). Stays mounted at all times so
              chat/analysis state survives closing and reopening the panel. */}
          <motion.div
            className="relative shrink-0 overflow-hidden border-l border-border"
            initial={false}
            animate={{ width: aiPanelOpen ? aiPanelWidth : 0 }}
            transition={{ duration: isResizingAiPanel ? 0 : 0.12, ease: 'easeOut' }}
            style={{ pointerEvents: aiPanelOpen ? 'auto' : 'none' }}
          >
            <div
              className="absolute left-0 top-0 z-10 h-full w-1 cursor-col-resize transition-colors hover:bg-primary/30"
              onMouseDown={(e) => {
                aiPanelDragRef.current = { x: e.clientX, width: aiPanelWidth }
                setIsResizingAiPanel(true)
                globalThis.document.body.style.cursor = 'col-resize'
                globalThis.document.body.style.userSelect = 'none'
              }}
            />
            <motion.div
              className="absolute inset-0 overflow-y-auto"
              style={{ width: aiPanelWidth }}
              initial={false}
              animate={{ opacity: aiPanelOpen ? 1 : 0, x: aiPanelOpen ? 0 : 16 }}
              transition={{ duration: 0.12, ease: 'easeOut' }}
            >
              <AiPanel
                editor={null}
                fileType="sheet"
                getDocumentContent={getSheetContext}
                onInsertFormula={onInsertFormula}
                onInsertTableData={onInsertTableData}
                actionHandler={aiActionHandler}
                extraTab={{
                  label: 'Insights',
                  icon: Lightbulb,
                  content: (
                    <SheetInsightsTab
                      getSheetContext={getSheetContext}
                      onInsertFormula={insightsInsertFormula}
                      onInsertChart={insightsInsertChart}
                    />
                  ),
                }}
              />
            </motion.div>
          </motion.div>
        </div>

        <SheetTabBar
          tabs={tabs}
          activeTabId={activeTabId}
          onTabChange={switchTab}
          onAddTab={addTab}
          onRenameTab={renameTab}
          onDeleteTab={deleteTab}
          zoom={zoom}
          onZoomChange={handleZoomChange}
          saveStatus={saveStatus}
          nowPlaying={music?.nowPlayingTitle ?? null}
          ambientPlaying={ambientPlaying}
        />
      </div>

      {settingsOpen && (
        <SettingsModal open={settingsOpen} onClose={() => setSettingsOpen(false)} />
      )}
      {exportOpen && (
        <SheetExportModal
          open={exportOpen}
          onClose={() => setExportOpen(false)}
          sheetTitle={doc?.title ?? 'Sheet'}
          workbookRef={workbookRef}
        />
      )}
      {chartDialogOpen && (
        <ChartDialog
          open={chartDialogOpen}
          onClose={() => { setChartDialogOpen(false); setEditingChart(undefined) }}
          workbookRef={workbookRef}
          activeSheetId={activeTabId}
          initialRange={editingChart ? editingChart.dataRange : getInitialChartRange()}
          editChart={editingChart}
          onInsert={handleInsertChart}
          onUpdate={handleUpdateChart}
        />
      )}
    </TooltipProvider>
  )
}

import { useRef, useState, useEffect, useCallback, useMemo } from 'react'
import type { Slide, PresentationTheme, PresentationSettings, SlideElement, ShapeElement, ShapeType } from '@/types/slides'
import { getSlideBaseSize } from '@/types/slides'
import { SlideBackgroundLayer } from './SlideBackground'
import { SlideElementWrapper } from './SlideElementWrapper'
import { MarqueeSelection } from './MarqueeSelection'
import { SlideGridOverlay } from '../SlideGridOverlay'
import { useCanvasDrag } from './useCanvasDrag'
import { SnapOverlay } from './SnapOverlay'
import type { SnapOverlayHandle } from './SnapOverlay'
import type { SnapHook } from './useCanvasDrag'
import type { SnapSettings } from './snapUtils'
import { ShapeElementRenderer } from '../elements/ShapeElementRenderer'
import { renderSlideElement } from '../elements/renderSlideElement'
import type { HandleType, ElementMove, ElementResize, ElementRotate, MarqueeRect } from './types'

export type CanvasToolMode = 'select' | 'text' | 'shape' | 'image' | 'table' | 'equation' | 'code' | 'video'

interface Props {
  slide: Slide
  theme: PresentationTheme
  settings: PresentationSettings
  selectedIds: string[]
  toolMode?: CanvasToolMode
  onSelectElement(id: string, addToSelection: boolean): void
  onDeselectAll(): void
  onDoubleClickElement(id: string): void
  onCommitText?(id: string, content: string): void
  editingElementId?: string | null
  onMoveElements(moves: ElementMove[]): void
  onResizeElement(resize: ElementResize): void
  onRotateElement(rotate: ElementRotate): void
  onMarqueeSelect(ids: string[]): void
  onDrawElement?(type: CanvasToolMode, x: number, y: number, width: number, height: number): void
  onCommitElement?(id: string, partial: Partial<SlideElement>): void
  onElementContextMenu?(e: React.MouseEvent, id: string): void
  onCanvasContextMenu?(e: React.MouseEvent): void
  showGrid?: boolean
  zoom?: number  // 0 = fit, 25–400 = explicit %
  onFitZoomChange?(pct: number): void
  onCanvasRectChange?(rect: { width: number; height: number; top: number; left: number }): void
  pendingShapeType?: ShapeType | null
  pendingTableConfig?: { cols: number; rows: number } | null
  onTableCellSelect?: (cellIds: string[]) => void
  snapSettings?: SnapSettings
}


// Compute multi-selection bounding box in percentages.
function multiSelectBounds(slide: Slide, ids: string[]): { x: number; y: number; w: number; h: number } | null {
  if (ids.length < 2) return null
  const els = slide.elements.filter((e) => ids.includes(e.id))
  if (els.length === 0) return null
  const minX = Math.min(...els.map((e) => e.x))
  const minY = Math.min(...els.map((e) => e.y))
  const maxX = Math.max(...els.map((e) => e.x + e.width))
  const maxY = Math.max(...els.map((e) => e.y + e.height))
  return { x: minX, y: minY, w: maxX - minX, h: maxY - minY }
}

export function SlideCanvas({
  slide,
  theme,
  settings,
  selectedIds,
  toolMode = 'select',
  onSelectElement,
  onDeselectAll,
  onDoubleClickElement,
  editingElementId = null,
  onCommitText,
  onCommitElement,
  onMoveElements,
  onResizeElement,
  onRotateElement,
  onMarqueeSelect,
  onDrawElement,
  onElementContextMenu,
  onCanvasContextMenu,
  showGrid = false,
  zoom = 0,
  onFitZoomChange,
  onCanvasRectChange,
  pendingShapeType,
  pendingTableConfig,
  onTableCellSelect,
  snapSettings,
}: Props): JSX.Element {
  const containerRef = useRef<HTMLDivElement>(null)
  const canvasRef = useRef<HTMLDivElement>(null)
  const elementRefs = useRef<Map<string, HTMLDivElement>>(new Map())
  const slideRef = useRef(slide)
  useEffect(() => { slideRef.current = slide }, [slide])

  // ── Snap engine ─────────────────────────────────────────────────────────────
  const overlayRef = useRef<SnapOverlayHandle>(null)
  const snapSelectedIdsRef = useRef(selectedIds)
  useEffect(() => { snapSelectedIdsRef.current = selectedIds }, [selectedIds])
  const snapSettingsRef = useRef<SnapSettings>(snapSettings ?? { enabled: true, toCanvas: true, toElements: true, equalSpacing: true })
  useEffect(() => { snapSettingsRef.current = snapSettings ?? { enabled: true, toCanvas: true, toElements: true, equalSpacing: true } }, [snapSettings])

  const snapHookRef = useRef<SnapHook>({
    getSettings: () => snapSettingsRef.current,
    getSlide: () => slideRef.current,
    getSelectedIds: () => snapSelectedIdsRef.current,
    getOverlay: () => overlayRef.current,
  })

  const [canvasSize, setCanvasSize] = useState({ width: 960, height: 540 })
  const [marqueeRect, setMarqueeRect] = useState<MarqueeRect | null>(null)
  const [ghostRect, setGhostRect] = useState<{ x: number; y: number; w: number; h: number } | null>(null)

  const { baseW, baseH } = getSlideBaseSize(settings)
  const scale = canvasSize.width / baseW

  const onFitZoomChangeRef = useRef(onFitZoomChange)
  useEffect(() => { onFitZoomChangeRef.current = onFitZoomChange }, [onFitZoomChange])

  // Fit canvas to container while maintaining aspect ratio. Zoom overrides fit.
  useEffect(() => {
    const el = containerRef.current
    if (!el) return
    function update(): void {
      if (!el) return
      if (zoom > 0) {
        // Explicit zoom: canvas is zoom% of base dimensions
        const factor = zoom / 100
        setCanvasSize({ width: baseW * factor, height: baseH * factor })
        return
      }
      // Fit mode
      const { width, height } = el.getBoundingClientRect()
      const pad = 40
      const availW = Math.max(1, width - pad * 2)
      const availH = Math.max(1, height - pad * 2)
      const ratio = baseW / baseH
      const byWidth = { width: availW, height: availW / ratio }
      let fitW: number
      if (byWidth.height <= availH) {
        setCanvasSize(byWidth)
        fitW = byWidth.width
      } else {
        const size = { width: availH * ratio, height: availH }
        setCanvasSize(size)
        fitW = size.width
      }
      onFitZoomChangeRef.current?.(Math.round((fitW / baseW) * 100))
    }
    update()
    if (zoom > 0) return  // no ResizeObserver needed when explicit zoom
    const obs = new ResizeObserver(update)
    obs.observe(el)
    return () => obs.disconnect()
  }, [baseW, baseH, zoom])

  const onCanvasRectChangeRef = useRef(onCanvasRectChange)
  useEffect(() => { onCanvasRectChangeRef.current = onCanvasRectChange }, [onCanvasRectChange])

  // Reports the canvas's live on-screen rect (viewport-relative) so callers — e.g.
  // the transition/animation preview overlay — can mirror its exact position and
  // zoom. Re-measures on size changes, container layout shifts (sidebar toggling),
  // scrolling (relevant in explicit-zoom mode, where the container scrolls), and
  // window resizes.
  useEffect(() => {
    const canvasEl = canvasRef.current
    const containerEl = containerRef.current
    if (!canvasEl || !containerEl) return
    function report(): void {
      const r = canvasEl!.getBoundingClientRect()
      onCanvasRectChangeRef.current?.({ width: r.width, height: r.height, top: r.top, left: r.left })
    }
    report()
    const ro = new ResizeObserver(report)
    ro.observe(containerEl)
    containerEl.addEventListener('scroll', report)
    window.addEventListener('resize', report)
    return () => {
      ro.disconnect()
      containerEl.removeEventListener('scroll', report)
      window.removeEventListener('resize', report)
    }
  }, [canvasSize])

  const registerRef = useCallback((id: string, el: HTMLDivElement | null): void => {
    if (el) elementRefs.current.set(id, el)
    else elementRefs.current.delete(id)
  }, [])

  const { startDrag } = useCanvasDrag({
    elementRefs,
    slideRef,
    setMarqueeRect,
    onMoveElements,
    onResizeElement,
    onRotateElement,
    onMarqueeSelect,
    snapHookRef,
  })

  const handleElementMouseDown = useCallback((e: React.MouseEvent, id: string): void => {
    e.stopPropagation()
    const addToSelection = e.shiftKey

    // Select first, then prepare drag
    onSelectElement(id, addToSelection)

    const element = slideRef.current.elements.find((el) => el.id === id)
    if (!element) return

    const canvasRect = canvasRef.current!.getBoundingClientRect()

    // Build start positions for all elements that will be dragged.
    const dragIds = addToSelection
      ? [id]
      : selectedIds.includes(id)
        ? selectedIds
        : [id]

    const startPositions = new Map<string, { x: number; y: number; rotate: number; flipH: boolean; flipV: boolean }>()
    for (const eid of dragIds) {
      const el = slideRef.current.elements.find((x) => x.id === eid)
      if (el) startPositions.set(eid, { x: el.x, y: el.y, rotate: el.rotate, flipH: el.flipH, flipV: el.flipV })
    }

    startDrag({
      type: 'move',
      elementIds: dragIds,
      startMouseX: e.clientX,
      startMouseY: e.clientY,
      startPositions,
      canvasRect,
    })
  }, [onSelectElement, selectedIds, startDrag])

  const handleResizeMouseDown = useCallback((e: React.MouseEvent, id: string, handle: HandleType): void => {
    e.stopPropagation()
    const element = slideRef.current.elements.find((el) => el.id === id)
    if (!element) return
    const canvasRect = canvasRef.current!.getBoundingClientRect()
    startDrag({
      type: 'resize',
      elementId: id,
      handle,
      startMouseX: e.clientX,
      startMouseY: e.clientY,
      startBounds: { x: element.x, y: element.y, width: element.width, height: element.height },
      canvasRect,
    })
  }, [startDrag])

  const handleRotateMouseDown = useCallback((e: React.MouseEvent, id: string): void => {
    e.stopPropagation()
    const el = elementRefs.current.get(id)
    if (!el) return
    const rect = el.getBoundingClientRect()
    const canvasRect = canvasRef.current!.getBoundingClientRect()
    const centerXAbs = rect.left + rect.width / 2
    const centerYAbs = rect.top + rect.height / 2
    const element = slideRef.current.elements.find((x) => x.id === id)
    const startAngle = element?.rotate ?? 0
    startDrag({ type: 'rotate', elementId: id, centerXAbs, centerYAbs, currentAngle: startAngle, canvasRect })
  }, [startDrag])

  const drawStartRef = useRef<{ x: number; y: number } | null>(null)

  // Handles mousedown on the entire interaction area (canvas + surrounding whitespace).
  // Element mousedowns call stopPropagation, so this only fires for background/whitespace clicks.
  const handleContainerMouseDown = useCallback((e: React.MouseEvent): void => {
    if (e.button !== 0) return  // only left-click draws/marquee-selects; right-click opens the context menu
    if (!canvasRef.current) return

    if (toolMode !== 'select' && onDrawElement) {
      // Captured into a const so the nested onMove/onUp closures below keep
      // the non-undefined narrowing — TS can't carry an outer `if` check's
      // narrowing of an optional prop into a nested `function` declaration.
      const draw = onDrawElement
      const canvasRect = canvasRef.current.getBoundingClientRect()
      const startX = ((e.clientX - canvasRect.left) / canvasRect.width) * 100
      const startY = ((e.clientY - canvasRect.top) / canvasRect.height) * 100
      drawStartRef.current = { x: startX, y: startY }

      const onMove = (ev: MouseEvent): void => {
        if (!drawStartRef.current || !canvasRef.current) return
        const rect = canvasRef.current.getBoundingClientRect()
        const endX = ((ev.clientX - rect.left) / rect.width) * 100
        const endY = ((ev.clientY - rect.top) / rect.height) * 100
        setGhostRect({
          x: Math.min(drawStartRef.current.x, endX),
          y: Math.min(drawStartRef.current.y, endY),
          w: Math.abs(endX - drawStartRef.current.x),
          h: Math.abs(endY - drawStartRef.current.y),
        })
      }

      const onUp = (ev: MouseEvent): void => {
        window.removeEventListener('mousemove', onMove)
        window.removeEventListener('mouseup', onUp)
        setGhostRect(null)
        if (!drawStartRef.current || !canvasRef.current) return
        const rect = canvasRef.current.getBoundingClientRect()
        const endX = ((ev.clientX - rect.left) / rect.width) * 100
        const endY = ((ev.clientY - rect.top) / rect.height) * 100
        const x = Math.min(drawStartRef.current.x, endX)
        const y = Math.min(drawStartRef.current.y, endY)
        const width = Math.abs(endX - drawStartRef.current.x)
        const height = Math.abs(endY - drawStartRef.current.y)
        if (width > 2 && height > 2) {
          draw(toolMode, x, y, width, height)
        } else {
          const cx = drawStartRef.current.x
          const cy = drawStartRef.current.y
          if (toolMode === 'text') {
            draw(toolMode, cx, cy - 2, 30, 10)
          } else if (toolMode === 'shape') {
            draw(toolMode, cx, cy, 15, 15)
          } else if (toolMode === 'table') {
            draw(toolMode, cx, cy, 35, 20)
          } else if (toolMode === 'equation') {
            draw(toolMode, cx, cy, 25, 12)
          } else if (toolMode === 'code') {
            draw(toolMode, cx, cy, 35, 20)
          } else {
            draw(toolMode, cx, cy, 30, 20)
          }
        }
        drawStartRef.current = null
      }

      window.addEventListener('mousemove', onMove)
      window.addEventListener('mouseup', onUp)
      return
    }

    onDeselectAll()
    const canvasRect = canvasRef.current.getBoundingClientRect()
    const startX = ((e.clientX - canvasRect.left) / canvasRect.width) * 100
    const startY = ((e.clientY - canvasRect.top) / canvasRect.height) * 100
    startDrag({ type: 'marquee', canvasRect, startX, startY })
  }, [toolMode, onDrawElement, onDeselectAll, startDrag])

  const sortedElements = useMemo(
    () => [...slide.elements].sort((a, b) => a.zIndex - b.zIndex),
    [slide.elements],
  )

  const multiBounds = useMemo(
    () => (selectedIds.length >= 2 ? multiSelectBounds(slide, selectedIds) : null),
    [slide, selectedIds],
  )

  return (
    <div
      ref={containerRef}
      style={{
        flex: 1,
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        overflow: zoom > 0 ? 'auto' : 'hidden',
        padding: zoom > 0 ? 24 : 0,
        backgroundColor: 'hsl(var(--editor-canvas))',
        cursor: toolMode !== 'select' ? 'crosshair' : 'default',
      }}
      onMouseDown={handleContainerMouseDown}
      onContextMenu={(e) => { e.preventDefault(); onCanvasContextMenu?.(e) }}
    >
      <div
        ref={canvasRef}
        style={{
          position: 'relative',
          width: canvasSize.width,
          height: canvasSize.height,
          flexShrink: 0,
          boxShadow: '0 4px 32px rgba(0,0,0,0.18)',
          // overflow: visible so elements dragged outside the slide remain visible in the
          // surrounding grey area. The background and master layers use their own clip div.
          overflow: 'visible',
          userSelect: 'none',
        }}
      >
        {/* Slide background — clipped to canvas bounds */}
        <div style={{ position: 'absolute', inset: 0, overflow: 'hidden', zIndex: 0, pointerEvents: 'none' }}>
          <SlideBackgroundLayer background={slide.background} theme={theme} />
        </div>

        {/* Slide elements — overflow: visible so they render in surrounding whitespace */}
        <div style={{ position: 'absolute', inset: 0, zIndex: 1 }}>
          {sortedElements.map((element) => (
            <SlideElementWrapper
              key={element.id}
              element={element}
              scale={scale}
              selected={selectedIds.includes(element.id)}
              isMultiSelected={selectedIds.length >= 2 && selectedIds.includes(element.id)}
              editingElementId={editingElementId}
              onElementMouseDown={handleElementMouseDown}
              onElementDoubleClick={(e, id) => { e.stopPropagation(); onDoubleClickElement(id) }}
              onResizeMouseDown={handleResizeMouseDown}
              onRotateMouseDown={handleRotateMouseDown}
              onElementContextMenu={(e, id) => onElementContextMenu?.(e, id)}
              registerRef={registerRef}
              onCommitText={(id, content) => onCommitText?.(id, content)}
              onCommitElement={(id, partial) => onCommitElement?.(id, partial)}
              onCancelEdit={() => onDoubleClickElement('')}
              onTableCellSelect={onTableCellSelect}
            />
          ))}
        </div>

        {/* Multi-selection bounding box */}
        {multiBounds && (
          <div
            style={{
              position: 'absolute',
              left: `${multiBounds.x}%`,
              top: `${multiBounds.y}%`,
              width: `${multiBounds.w}%`,
              height: `${multiBounds.h}%`,
              border: '1.5px dashed hsl(var(--primary))',
              pointerEvents: 'none',
              zIndex: 9998,
            }}
          />
        )}

        {ghostRect && ghostRect.w > 0.5 && ghostRect.h > 0.5 && (() => {
          const ghostStyle: React.CSSProperties = {
            position: 'absolute',
            left: `${ghostRect.x}%`,
            top: `${ghostRect.y}%`,
            width: `${ghostRect.w}%`,
            height: `${ghostRect.h}%`,
            pointerEvents: 'none',
            zIndex: 9999,
          }
          if (toolMode === 'shape' && pendingShapeType) {
            const ghostEl: ShapeElement = {
              id: 'ghost', type: 'shape', shapeType: pendingShapeType,
              fill: 'hsl(var(--primary) / 0.12)',
              border: { color: 'hsl(var(--primary))', width: 2, style: 'solid' },
              x: 0, y: 0, width: 100, height: 100,
              rotate: 0, opacity: 1, zIndex: 0, flipH: false, flipV: false, locked: false, hidden: false,
            }
            return (
              <div style={ghostStyle}>
                <ShapeElementRenderer element={ghostEl} scale={scale} />
              </div>
            )
          }
          if (toolMode === 'table' && pendingTableConfig) {
            const { cols, rows } = pendingTableConfig
            return (
              <div style={{ ...ghostStyle, border: '1.5px solid hsl(var(--primary))', backgroundColor: 'hsl(var(--primary) / 0.04)' }}>
                <svg width="100%" height="100%" style={{ display: 'block' }}>
                  {Array.from({ length: cols - 1 }, (_, i) => {
                    const x = ((i + 1) / cols) * 100
                    return <line key={`c${i}`} x1={`${x}%`} y1="0" x2={`${x}%`} y2="100%" stroke="hsl(var(--primary))" strokeWidth="1" />
                  })}
                  {Array.from({ length: rows - 1 }, (_, i) => {
                    const y = ((i + 1) / rows) * 100
                    return <line key={`r${i}`} x1="0" y1={`${y}%`} x2="100%" y2={`${y}%`} stroke="hsl(var(--primary))" strokeWidth="1" />
                  })}
                </svg>
              </div>
            )
          }
          return (
            <div
              style={{
                ...ghostStyle,
                border: '1.5px dashed hsl(var(--primary))',
                backgroundColor: 'hsl(var(--primary) / 0.06)',
              }}
            />
          )
        })()}

        {marqueeRect && <MarqueeSelection rect={marqueeRect} />}

        {/* Snap guides overlay — pointer-events:none, above elements */}
        <SnapOverlay ref={overlayRef} />

        {/* Grid overlay — clipped to canvas bounds, no explicit z-index so it stays below any portal modals */}
        {showGrid && (
          <div style={{ position: 'absolute', inset: 0, overflow: 'hidden', pointerEvents: 'none' }}>
            <SlideGridOverlay canvasWidth={canvasSize.width} canvasHeight={canvasSize.height} />
          </div>
        )}
      </div>
    </div>
  )
}

import { useRef, useCallback } from 'react'
import type { Slide } from '@/types/slides'
import type { DragState, HandleType, ElementMove, ElementResize, ElementRotate, MarqueeRect } from './types'
import {
  computeSnapTargets, applyMoveSnap, applyResizeSnap, applyRotationSnap, snapThreshold,
  type SnapSettings, type SnapTargetList, type BoundsRect,
} from './snapUtils'
import type { SnapOverlayHandle } from './SnapOverlay'

const DRAG_THRESHOLD_PX = 4
const MIN_ELEMENT_PERCENT = 2
const ROTATE_SNAP_THRESHOLD_DEG = 5

function applyResizeHandle(
  bounds: { x: number; y: number; width: number; height: number },
  handle: HandleType,
  dx: number,
  dy: number,
  shiftKey: boolean,
): { x: number; y: number; width: number; height: number } {
  let { x, y, width, height } = bounds
  switch (handle) {
    case 'nw': x += dx; y += dy; width -= dx; height -= dy; break
    case 'n':  y += dy; height -= dy; break
    case 'ne': width += dx; y += dy; height -= dy; break
    case 'e':  width += dx; break
    case 'se': width += dx; height += dy; break
    case 's':  height += dy; break
    case 'sw': x += dx; width -= dx; height += dy; break
    case 'w':  x += dx; width -= dx; break
  }
  if (shiftKey && (handle === 'nw' || handle === 'ne' || handle === 'se' || handle === 'sw')) {
    const ar = bounds.width / (bounds.height || 1)
    width = Math.max(MIN_ELEMENT_PERCENT, width)
    height = width / ar
  }
  width = Math.max(MIN_ELEMENT_PERCENT, width)
  height = Math.max(MIN_ELEMENT_PERCENT, height)
  return { x, y, width, height }
}

export interface SnapHook {
  getSettings(): SnapSettings
  getSlide(): Slide
  getSelectedIds(): string[]
  getOverlay(): SnapOverlayHandle | null
}

interface Params {
  elementRefs: React.MutableRefObject<Map<string, HTMLDivElement>>
  slideRef: React.MutableRefObject<Slide>
  setMarqueeRect(rect: MarqueeRect | null): void
  onMoveElements(moves: ElementMove[]): void
  onResizeElement(resize: ElementResize): void
  onRotateElement(rotate: ElementRotate): void
  onMarqueeSelect(ids: string[]): void
  snapHookRef?: React.MutableRefObject<SnapHook>
}

export function useCanvasDrag({
  elementRefs,
  slideRef,
  setMarqueeRect,
  onMoveElements,
  onResizeElement,
  onRotateElement,
  onMarqueeSelect,
  snapHookRef,
}: Params) {
  const dragStateRef = useRef<DragState | null>(null)

  // Callbacks stored in ref so closures in startDrag never go stale.
  const cbRef = useRef({ onMoveElements, onResizeElement, onRotateElement, onMarqueeSelect, setMarqueeRect })
  cbRef.current = { onMoveElements, onResizeElement, onRotateElement, onMarqueeSelect, setMarqueeRect }

  // Snap state — precomputed at drag start, consumed during mousemove
  const snapRef = useRef<{
    targets: SnapTargetList
    // For move: bounding box of all dragged elements at start position
    moveBBox?: BoundsRect
  } | null>(null)

  const startDrag = useCallback((state: DragState): void => {
    dragStateRef.current = state
    document.body.style.userSelect = 'none'

    // Precompute snap targets once on drag start
    snapRef.current = null
    const hook = snapHookRef?.current
    if (hook && hook.getSettings().enabled && (state.type === 'move' || state.type === 'resize')) {
      const targets = computeSnapTargets(hook.getSlide(), hook.getSelectedIds(), hook.getSettings())
      let moveBBox: BoundsRect | undefined

      if (state.type === 'move') {
        // Compute bounding box of all dragged elements
        const slide = hook.getSlide()
        let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity
        for (const [id, pos] of state.startPositions) {
          const el = slide.elements.find((e) => e.id === id)
          if (!el) continue
          minX = Math.min(minX, pos.x)
          minY = Math.min(minY, pos.y)
          maxX = Math.max(maxX, pos.x + el.width)
          maxY = Math.max(maxY, pos.y + el.height)
        }
        if (isFinite(minX)) {
          moveBBox = { x: minX, y: minY, w: maxX - minX, h: maxY - minY }
        }
      }

      snapRef.current = { targets, moveBBox }
    }

    function onMove(e: MouseEvent): void {
      const ds = dragStateRef.current
      if (!ds) return

      if (ds.type === 'move') {
        const rawDeltaXPx = e.clientX - ds.startMouseX
        const rawDeltaYPx = e.clientY - ds.startMouseY

        let appliedDeltaXPx = rawDeltaXPx
        let appliedDeltaYPx = rawDeltaYPx

        const snap = snapRef.current
        const hook = snapHookRef?.current
        if (snap && hook && !e.altKey) {
          const settings = hook.getSettings()
          if (settings.enabled && snap.moveBBox) {
            const threshold = snapThreshold(ds.canvasRect.width)
            const rawDxPct = (rawDeltaXPx / ds.canvasRect.width) * 100
            const rawDyPct = (rawDeltaYPx / ds.canvasRect.height) * 100
            const rawBBox: BoundsRect = {
              x: snap.moveBBox.x + rawDxPct,
              y: snap.moveBBox.y + rawDyPct,
              w: snap.moveBBox.w,
              h: snap.moveBBox.h,
            }
            const result = applyMoveSnap(
              rawBBox, snap.targets, threshold,
              hook.getSlide(), hook.getSelectedIds(), settings,
            )
            const corrXPct = result.x - rawBBox.x
            const corrYPct = result.y - rawBBox.y
            appliedDeltaXPx = rawDeltaXPx + (corrXPct / 100) * ds.canvasRect.width
            appliedDeltaYPx = rawDeltaYPx + (corrYPct / 100) * ds.canvasRect.height
            hook.getOverlay()?.update(result.guides, result.spacing)
          }
        } else if (!snap && hook) {
          hook.getOverlay()?.clear()
        }

        for (const id of ds.elementIds) {
          const el = elementRefs.current.get(id)
          const pos = ds.startPositions.get(id)
          if (!el || !pos) continue
          const flip = `scaleX(${pos.flipH ? -1 : 1}) scaleY(${pos.flipV ? -1 : 1})`
          el.style.transform = `translate(${appliedDeltaXPx}px, ${appliedDeltaYPx}px) rotate(${pos.rotate}deg) ${flip}`
        }
        return
      }

      if (ds.type === 'resize') {
        const el = elementRefs.current.get(ds.elementId)
        if (!el) return
        const dx = ((e.clientX - ds.startMouseX) / ds.canvasRect.width) * 100
        const dy = ((e.clientY - ds.startMouseY) / ds.canvasRect.height) * 100
        let nb = applyResizeHandle(ds.startBounds, ds.handle, dx, dy, e.shiftKey)

        const snap = snapRef.current
        const hook = snapHookRef?.current
        if (snap && hook && !e.altKey && hook.getSettings().enabled) {
          const threshold = snapThreshold(ds.canvasRect.width)
          const { bounds: snappedBounds, guides } = applyResizeSnap(
            ds.handle, nb, snap.targets, threshold,
          )
          nb = snappedBounds
          hook.getOverlay()?.update(guides, [])
        }

        el.style.left = `${nb.x}%`
        el.style.top = `${nb.y}%`
        el.style.width = `${nb.width}%`
        el.style.height = `${nb.height}%`
        return
      }

      if (ds.type === 'rotate') {
        const el = elementRefs.current.get(ds.elementId)
        if (!el) return
        let angle = Math.atan2(e.clientY - ds.centerYAbs, e.clientX - ds.centerXAbs) * (180 / Math.PI) + 90

        const hook = snapHookRef?.current
        const settings = hook?.getSettings()
        if (settings?.enabled && !e.altKey) {
          angle = applyRotationSnap(angle)
        } else if (e.shiftKey) {
          // Legacy Shift-key snap when master snap disabled
          const snapped = Math.round(angle / 45) * 45
          if (Math.abs(angle - snapped) < ROTATE_SNAP_THRESHOLD_DEG) angle = snapped
        }

        el.style.transform = `rotate(${angle}deg)`
        dragStateRef.current = { ...ds, currentAngle: angle }

        // Show angle label
        if (hook && ds.canvasRect) {
          const cx = ((ds.centerXAbs - ds.canvasRect.left) / ds.canvasRect.width) * 100
          const cy = ((ds.centerYAbs - ds.canvasRect.top) / ds.canvasRect.height) * 100
          hook.getOverlay()?.update([], [], angle, cx, cy)
        }
        return
      }

      if (ds.type === 'marquee') {
        const endX = ((e.clientX - ds.canvasRect.left) / ds.canvasRect.width) * 100
        const endY = ((e.clientY - ds.canvasRect.top) / ds.canvasRect.height) * 100
        cbRef.current.setMarqueeRect({ startX: ds.startX, startY: ds.startY, endX, endY })
      }
    }

    function onUp(e: MouseEvent): void {
      document.body.style.userSelect = ''
      window.removeEventListener('mousemove', onMove)
      window.removeEventListener('mouseup', onUp)

      // Clear overlay
      snapHookRef?.current?.getOverlay()?.clear()
      snapRef.current = null

      const ds = dragStateRef.current
      dragStateRef.current = null

      if (!ds) return

      if (ds.type === 'move') {
        const totalDelta = Math.hypot(e.clientX - ds.startMouseX, e.clientY - ds.startMouseY)
        if (totalDelta < DRAG_THRESHOLD_PX) {
          // Was a click — restore transforms without committing
          for (const id of ds.elementIds) {
            const el = elementRefs.current.get(id)
            const pos = ds.startPositions.get(id)
            if (el && pos) {
              const flip = `scaleX(${pos.flipH ? -1 : 1}) scaleY(${pos.flipV ? -1 : 1})`
              el.style.transform = `rotate(${pos.rotate}deg) ${flip}`
            }
          }
          return
        }

        // Recompute final positions with snap applied
        const hook = snapHookRef?.current
        let corrXPct = 0
        let corrYPct = 0

        const rawDxPx = e.clientX - ds.startMouseX
        const rawDyPx = e.clientY - ds.startMouseY
        const rawDxPct = (rawDxPx / ds.canvasRect.width) * 100
        const rawDyPct = (rawDyPx / ds.canvasRect.height) * 100

        // Recompute snap correction using same logic as onMove
        const snapState = (() => {
          if (!hook || !hook.getSettings().enabled || e.altKey) return null
          const slide = hook.getSlide()
          const selectedIds = hook.getSelectedIds()
          const targets = computeSnapTargets(slide, selectedIds, hook.getSettings())
          let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity
          for (const [id, pos] of ds.startPositions) {
            const el = slide.elements.find((x) => x.id === id)
            if (!el) continue
            minX = Math.min(minX, pos.x); minY = Math.min(minY, pos.y)
            maxX = Math.max(maxX, pos.x + el.width); maxY = Math.max(maxY, pos.y + el.height)
          }
          if (!isFinite(minX)) return null
          const rawBBox: BoundsRect = { x: minX + rawDxPct, y: minY + rawDyPct, w: maxX - minX, h: maxY - minY }
          return applyMoveSnap(rawBBox, targets, snapThreshold(ds.canvasRect.width), slide, selectedIds, hook.getSettings())
        })()

        if (snapState) {
          // snapState.x/.y is the snapped bbox origin; original bbox origin was (minX + rawDxPct)
          // We need correction relative to the raw delta
          let minX = Infinity, minY = Infinity
          for (const [, pos] of ds.startPositions) { minX = Math.min(minX, pos.x); minY = Math.min(minY, pos.y) }
          corrXPct = snapState.x - (minX + rawDxPct)
          corrYPct = snapState.y - (minY + rawDyPct)
        }

        const moves: ElementMove[] = []
        for (const id of ds.elementIds) {
          const el = elementRefs.current.get(id)
          const pos = ds.startPositions.get(id)
          if (!el || !pos) continue
          const newX = pos.x + rawDxPct + corrXPct
          const newY = pos.y + rawDyPct + corrYPct
          const flip = `scaleX(${pos.flipH ? -1 : 1}) scaleY(${pos.flipV ? -1 : 1})`
          el.style.transform = `rotate(${pos.rotate}deg) ${flip}`
          el.style.left = `${newX}%`
          el.style.top = `${newY}%`
          moves.push({ id, x: newX, y: newY })
        }
        if (moves.length > 0) cbRef.current.onMoveElements(moves)
        return
      }

      if (ds.type === 'resize') {
        const dx = ((e.clientX - ds.startMouseX) / ds.canvasRect.width) * 100
        const dy = ((e.clientY - ds.startMouseY) / ds.canvasRect.height) * 100
        if (Math.abs(dx) < 0.5 && Math.abs(dy) < 0.5) return
        let nb = applyResizeHandle(ds.startBounds, ds.handle, dx, dy, e.shiftKey)

        // Apply snap on commit
        const hook = snapHookRef?.current
        if (hook && hook.getSettings().enabled && !e.altKey) {
          const targets = computeSnapTargets(hook.getSlide(), hook.getSelectedIds(), hook.getSettings())
          const { bounds: snapped } = applyResizeSnap(ds.handle, nb, targets, snapThreshold(ds.canvasRect.width))
          nb = snapped
        }

        cbRef.current.onResizeElement({ id: ds.elementId, ...nb })
        return
      }

      if (ds.type === 'rotate') {
        cbRef.current.onRotateElement({ id: ds.elementId, rotate: ds.currentAngle })
        return
      }

      if (ds.type === 'marquee') {
        cbRef.current.setMarqueeRect(null)
        const endX = ((e.clientX - ds.canvasRect.left) / ds.canvasRect.width) * 100
        const endY = ((e.clientY - ds.canvasRect.top) / ds.canvasRect.height) * 100
        const minX = Math.min(ds.startX, endX)
        const maxX = Math.max(ds.startX, endX)
        const minY = Math.min(ds.startY, endY)
        const maxY = Math.max(ds.startY, endY)
        if (maxX - minX < 0.5 && maxY - minY < 0.5) return
        const hit = slideRef.current.elements
          .filter((el) => !el.locked && !el.hidden)
          .filter((el) => el.x < maxX && el.x + el.width > minX && el.y < maxY && el.y + el.height > minY)
          .map((el) => el.id)
        cbRef.current.onMarqueeSelect(hit)
      }
    }

    window.addEventListener('mousemove', onMove)
    window.addEventListener('mouseup', onUp)
  }, [elementRefs, slideRef, snapHookRef])

  return { startDrag, dragStateRef }
}

import { useEffect, useRef, useState, useCallback } from 'react'
import type { TextElement } from '@/types/slides'
import { sanitizeRichText } from '@/lib/sanitizeHtml'

interface Props {
  element: TextElement
  scale: number
  onCommit(content: string): void
  onCancel(): void
}

// contenteditable overlay for in-place text editing.
// Commit on blur or Escape; the edited innerHTML becomes the new content.
export function TextElementEditor({ element, scale, onCommit, onCancel }: Props): JSX.Element {
  const divRef = useRef<HTMLDivElement>(null)
  const committedRef = useRef(false)
  const [isEmpty, setIsEmpty] = useState(!element.content || element.content === '' || element.content === '<br>')

  useEffect(() => {
    const el = divRef.current
    if (!el) return
    el.innerHTML = sanitizeRichText(element.content)
    el.focus()
    const range = document.createRange()
    range.selectNodeContents(el)
    range.collapse(false)
    const sel = window.getSelection()
    if (sel) { sel.removeAllRanges(); sel.addRange(range) }
  }, []) // run once on mount

  const commit = useCallback((): void => {
    if (committedRef.current) return
    committedRef.current = true
    const content = sanitizeRichText(divRef.current?.innerHTML ?? element.content)
    onCommit(content)
  }, [element.content, onCommit])

  const handleKeyDown = useCallback((e: React.KeyboardEvent): void => {
    if (e.key === 'Escape') {
      committedRef.current = true
      onCancel()
      return
    }
    if (e.key === 'Enter' && e.ctrlKey) {
      e.preventDefault()
      commit()
      e.stopPropagation()
      return
    }
    if (e.key === 'Enter' && e.shiftKey) {
      // In a list item: insert a plain line break instead of a new bullet
      const sel = window.getSelection()
      let inListItem = false
      if (sel && sel.rangeCount > 0) {
        let node: Node | null = sel.anchorNode
        while (node && node !== divRef.current) {
          if (node.nodeName === 'LI') { inListItem = true; break }
          node = node.parentNode
        }
      }
      e.preventDefault()
      if (inListItem) {
        document.execCommand('insertLineBreak')
      } else {
        commit()
      }
      e.stopPropagation()
      return
    }
    if (e.key === 'Tab') {
      e.preventDefault()
      // Indent/outdent only when cursor is inside a list item
      const sel = window.getSelection()
      if (sel && sel.rangeCount > 0) {
        let node: Node | null = sel.anchorNode
        while (node && node !== divRef.current) {
          if (node.nodeName === 'LI') {
            document.execCommand(e.shiftKey ? 'outdent' : 'indent')
            break
          }
          node = node.parentNode
        }
      }
      e.stopPropagation()
      return
    }
    e.stopPropagation()
  }, [commit, onCancel])

  const handleInput = useCallback((): void => {
    const el = divRef.current
    const empty = !el || !el.textContent?.trim()
    setIsEmpty(empty)
  }, [])

  const alignMap: Record<TextElement['align'], React.CSSProperties['textAlign']> = {
    left: 'left', center: 'center', right: 'right', justify: 'justify',
  }

  const vAlignMap: Record<TextElement['verticalAlign'], string> = {
    top: 'flex-start', middle: 'center', bottom: 'flex-end',
  }

  return (
    <div
      style={{
        position: 'absolute',
        inset: 0,
        display: 'flex',
        flexDirection: 'column',
        justifyContent: vAlignMap[element.verticalAlign],
        background: element.fill ?? 'transparent',
        padding: `${4 * scale}px`,
        boxSizing: 'border-box',
        cursor: 'text',
        zIndex: 1,
      }}
      onMouseDown={(e) => e.stopPropagation()}
    >
      <div style={{ position: 'relative', width: '100%' }}>
        {isEmpty && (
          <div
            style={{
              position: 'absolute',
              top: 0,
              left: 0,
              pointerEvents: 'none',
              userSelect: 'none',
              color: 'rgba(150,150,150,0.7)',
              fontFamily: element.fontFamily,
              fontSize: element.fontSize * scale,
              lineHeight: element.lineHeight,
              letterSpacing: element.letterSpacing * scale,
              textAlign: alignMap[element.align],
              whiteSpace: 'pre-wrap',
              width: '100%',
            }}
          >
            Enter your text here...
          </div>
        )}
        <div
          ref={divRef}
          className="slide-text-content"
          contentEditable
          suppressContentEditableWarning
          onBlur={commit}
          onKeyDown={handleKeyDown}
          onInput={handleInput}
          style={{
            outline: 'none',
            whiteSpace: 'pre-wrap',
            wordBreak: 'break-word',
            fontFamily: element.fontFamily,
            fontSize: element.fontSize * scale,
            color: element.color,
            textAlign: alignMap[element.align],
            lineHeight: element.lineHeight,
            letterSpacing: element.letterSpacing * scale,
            minHeight: 1,
            width: '100%',
          }}
        />
      </div>
    </div>
  )
}

