                onContextMenu={(e) => e.preventDefault()}
              />
            </div>
          ))}
        </div>
      </div>
    </div>
  )
}

import { createPortal } from 'react-dom'
import { Check } from 'lucide-react'
import { BUILT_IN_THEMES } from './builtInThemes'
import type { PresentationTheme, Slide } from '@/types/slides'
import { cn } from '@/lib/utils'

interface Props {
  theme: PresentationTheme
  slides: Slide[]
  onApplyTheme(theme: PresentationTheme, updatedSlides: Slide[]): void
  onClose(): void
  anchorRect: DOMRect
}

// When applying a theme, update slide backgrounds that still match the old theme default.
// Elements with manually set colors (not matching any known theme's textColor) are left alone.
function applyThemeToSlides(slides: Slide[], oldTheme: PresentationTheme, newTheme: PresentationTheme): Slide[] {
  return slides.map((slide) => ({
    ...slide,
    // Update background if it matched old theme
    background: slide.background?.type === 'solid' && slide.background.color === oldTheme.backgroundColor
      ? { ...slide.background, color: newTheme.backgroundColor }
      : slide.background,
    elements: slide.elements.map((el) => {
      if (el.type === 'text' && el.color === oldTheme.textColor) {
        return { ...el, color: newTheme.textColor, fontFamily: newTheme.bodyFontFamily }
      }
      return el
    }),
  }))
}

export function ThemePanel({ theme, slides, onApplyTheme, onClose, anchorRect }: Props): JSX.Element {
  function handleSelect(t: PresentationTheme) {
    const updatedSlides = applyThemeToSlides(slides, theme, t)
    onApplyTheme(t, updatedSlides)
    onClose()
  }

  return createPortal(
    <>
      {/* Backdrop */}
      <div className="fixed inset-0 z-[99990]" onClick={onClose} />

      <div
        className="fixed z-[99991] w-72 rounded-xl border border-border bg-background p-4 shadow-2xl"
        style={{ top: anchorRect.bottom + 8, right: window.innerWidth - anchorRect.right }}
      >
        <h3 className="mb-3 text-[13px] font-semibold text-foreground">Presentation theme</h3>

        <div className="grid grid-cols-2 gap-2">
          {BUILT_IN_THEMES.map((t) => (
            <button
              key={t.id}
              className={cn(
                'relative flex flex-col items-start gap-1 overflow-hidden rounded-lg border-2 p-0 transition-all hover:scale-[1.02]',
                theme.id === t.id ? 'border-primary' : 'border-border hover:border-border/80',
              )}
              onClick={() => handleSelect(t)}
            >
              {/* Color preview */}
              <div
                className="flex h-16 w-full items-center justify-center gap-1"
                style={{ background: t.backgroundColor }}
              >
                <div className="h-6 w-1.5 rounded-sm" style={{ background: t.primaryColor }} />
                <div className="h-4 w-1 rounded-sm" style={{ background: t.secondaryColor }} />
                <div
                  className="text-[10px] font-semibold"
                  style={{ color: t.textColor, fontFamily: t.headingFontFamily }}
                >
                  Aa
                </div>
              </div>

              <div className="w-full px-2 pb-2">
                <span className="text-[11px] font-medium text-foreground">{t.name}</span>
              </div>

              {theme.id === t.id && (
                <div className="absolute right-1.5 top-1.5 flex h-4 w-4 items-center justify-center rounded-full bg-primary">
                  <Check className="h-2.5 w-2.5 text-primary-foreground" />
                </div>
              )}
            </button>
          ))}
        </div>

        {/* Custom theme hint */}
        <p className="mt-3 text-[10px] text-muted-foreground/60">
          Applying a theme updates slides using the previous theme's default colors.
          Manually-customized elements are preserved.
        </p>
      </div>
    </>,
    document.body,
  )
}

import { useState, useRef, useEffect } from 'react'
import { HexColorPicker } from 'react-colorful'
import { createPortal } from 'react-dom'

const SWATCHES = [
  '#000000', '#ffffff', '#374151', '#6b7280', '#ef4444', '#f97316',
  '#eab308', '#22c55e', '#3b82f6', '#8b5cf6', '#ec4899', '#14b8a6',
]

interface Props {
  value: string
  onChange(color: string): void
  children: React.ReactNode
  label?: string
}

export function ColorPickerPopover({ value, onChange, children, label }: Props): JSX.Element {
  const [open, setOpen] = useState(false)
  const [hex, setHex] = useState(value)
  const [pos, setPos] = useState({ top: 0, left: 0 })
  const triggerRef = useRef<HTMLDivElement>(null)
  const popoverRef = useRef<HTMLDivElement>(null)

  // Sync external value
  useEffect(() => { setHex(value) }, [value])

  function handleOpen() {
    if (!triggerRef.current) return
    const r = triggerRef.current.getBoundingClientRect()
    setPos({ top: r.bottom + 4, left: r.left })
    setOpen((o) => !o)
  }

  useEffect(() => {
    if (!open) return
    function onDown(e: MouseEvent) {
      if (popoverRef.current?.contains(e.target as Node)) return
      if (triggerRef.current?.contains(e.target as Node)) return
      setOpen(false)
    }
    window.addEventListener('mousedown', onDown)
    return () => window.removeEventListener('mousedown', onDown)
  }, [open])

  function handleHexChange(v: string) {
    setHex(v)
    onChange(v)
  }

  function handleInputChange(e: React.ChangeEvent<HTMLInputElement>) {
    const v = e.target.value
    setHex(v)
    if (/^#[0-9a-fA-F]{6}$/.test(v)) onChange(v)
  }

  return (
    <>
      <div ref={triggerRef} onClick={handleOpen} className="cursor-pointer" title={label}>
        {children}
      </div>

      {open && createPortal(
        <div
          ref={popoverRef}
          style={{ position: 'fixed', top: pos.top, left: pos.left, zIndex: 99999 }}
          className="rounded-lg border border-border bg-background p-3 shadow-xl"
        >
          <HexColorPicker color={hex} onChange={handleHexChange} style={{ width: 192, height: 140 }} />

          {/* Swatches */}
          <div className="mt-2 grid grid-cols-6 gap-1">
            {SWATCHES.map((s) => (
              <button
                key={s}
                className="h-5 w-5 rounded border border-border/50 transition-transform hover:scale-110"
                style={{ background: s }}
                onClick={() => handleHexChange(s)}
              />
            ))}
          </div>

          {/* Hex input */}
          <input
            type="text"
            value={hex}
            onChange={handleInputChange}
            maxLength={7}
            className="mt-2 w-full rounded border border-border bg-background px-2 py-1 font-mono text-xs focus:outline-none focus:ring-1 focus:ring-primary"
          />
        </div>,
        document.body,
      )}
    </>
  )
}

import {
  AlignStartHorizontal, AlignCenterHorizontal, AlignEndHorizontal,
  AlignStartVertical, AlignCenterVertical, AlignEndVertical,
  AlignHorizontalDistributeCenter, AlignVerticalDistributeCenter,
} from 'lucide-react'
import { Tooltip, TooltipContent, TooltipTrigger } from '@/components/ui/tooltip'
import { Button } from '@/components/ui/button'
import { Separator } from '@/components/ui/separator'
import type { Slide } from '@/types/slides'

interface Props {
  selectedIds: string[]
  slide: Slide
  onAlignElements(updates: { id: string; x: number; y: number }[]): void
}

export function MultiSelectToolbar({ selectedIds, slide, onAlignElements }: Props): JSX.Element {
  const elements = slide.elements.filter((e) => selectedIds.includes(e.id))

  function align(type: 'left' | 'center-h' | 'right' | 'top' | 'center-v' | 'bottom' | 'dist-h' | 'dist-v') {
    if (elements.length < 2) return

    const minX = Math.min(...elements.map((e) => e.x))
    const maxX = Math.max(...elements.map((e) => e.x + e.width))
    const minY = Math.min(...elements.map((e) => e.y))
    const maxY = Math.max(...elements.map((e) => e.y + e.height))

    let updates: { id: string; x: number; y: number }[]

    switch (type) {
      case 'left':
        updates = elements.map((e) => ({ id: e.id, x: minX, y: e.y }))
        break
      case 'center-h':
        updates = elements.map((e) => ({ id: e.id, x: (minX + maxX) / 2 - e.width / 2, y: e.y }))
        break
      case 'right':
        updates = elements.map((e) => ({ id: e.id, x: maxX - e.width, y: e.y }))
        break
      case 'top':
        updates = elements.map((e) => ({ id: e.id, x: e.x, y: minY }))
        break
      case 'center-v':
        updates = elements.map((e) => ({ id: e.id, x: e.x, y: (minY + maxY) / 2 - e.height / 2 }))
        break
      case 'bottom':
        updates = elements.map((e) => ({ id: e.id, x: e.x, y: maxY - e.height }))
        break
      case 'dist-h': {
        const sorted = [...elements].sort((a, b) => a.x - b.x)
        const totalW = sorted.reduce((s, e) => s + e.width, 0)
        const gap = (maxX - minX - totalW) / (sorted.length - 1)
        let cursor = minX
        updates = sorted.map((e) => { const u = { id: e.id, x: cursor, y: e.y }; cursor += e.width + gap; return u })
        break
      }
      case 'dist-v': {
        const sorted = [...elements].sort((a, b) => a.y - b.y)
        const totalH = sorted.reduce((s, e) => s + e.height, 0)
        const gap = (maxY - minY - totalH) / (sorted.length - 1)
        let cursor = minY
        updates = sorted.map((e) => { const u = { id: e.id, x: e.x, y: cursor }; cursor += e.height + gap; return u })
        break
      }
      default:
        return
    }

    onAlignElements(updates)
  }

  const alignButtons: { type: Parameters<typeof align>[0]; icon: React.ComponentType<{ className?: string }>; label: string }[] = [
    { type: 'left',     icon: AlignStartVertical,   label: 'Align left edges' },
    { type: 'center-h', icon: AlignCenterVertical,  label: 'Align centers (H)' },
    { type: 'right',    icon: AlignEndVertical,     label: 'Align right edges' },
    { type: 'top',      icon: AlignStartHorizontal, label: 'Align top edges' },
    { type: 'center-v', icon: AlignCenterHorizontal, label: 'Align centers (V)' },
    { type: 'bottom',   icon: AlignEndHorizontal,   label: 'Align bottom edges' },
  ]
  const distributeButtons: { type: Parameters<typeof align>[0]; icon: React.ComponentType<{ className?: string }>; label: string }[] = [
    { type: 'dist-h', icon: AlignHorizontalDistributeCenter, label: 'Distribute horizontally' },
    { type: 'dist-v', icon: AlignVerticalDistributeCenter,   label: 'Distribute vertically' },
  ]

  return (
    <div className="flex items-center gap-0.5">
      <span className="mr-1 text-[11px] text-muted-foreground">{selectedIds.length} selected</span>
      {alignButtons.map(({ type, icon: Icon, label }) => (
        <Tooltip key={type}>
          <TooltipTrigger asChild>
            <Button variant="ghost" size="icon" className="h-7 w-7" onClick={() => align(type)}>
              <Icon className="h-3.5 w-3.5" />
            </Button>
          </TooltipTrigger>
          <TooltipContent side="bottom" className="text-xs">{label}</TooltipContent>
        </Tooltip>
      ))}
      <Separator orientation="vertical" className="mx-0.5 h-5" />
      {distributeButtons.map(({ type, icon: Icon, label }) => (
        <Tooltip key={type}>
          <TooltipTrigger asChild>
            <Button variant="ghost" size="icon" className="h-7 w-7" onClick={() => align(type)}>
              <Icon className="h-3.5 w-3.5" />
            </Button>
          </TooltipTrigger>
          <TooltipContent side="bottom" className="text-xs">{label}</TooltipContent>
        </Tooltip>
      ))}
    </div>
  )
}

