const ALL_SHAPES: ShapeType[] = Object.keys(SHAPE_LABELS) as ShapeType[]

interface Props {
  children: React.ReactNode
  selectedShapeType?: ShapeType | null
  onSelect(shapeType: ShapeType): void
}

export function ShapePickerPopover({ children, selectedShapeType, onSelect }: Props): JSX.Element {
  const [open, setOpen] = useState(false)
  const [pos, setPos] = useState({ top: 0, left: 0 })
  const triggerRef = useRef<HTMLDivElement>(null)
  const popRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    if (!open) return
    function onDown(e: MouseEvent) {
      if (popRef.current?.contains(e.target as Node)) return
      if (triggerRef.current?.contains(e.target as Node)) return
      setOpen(false)
    }
    window.addEventListener('mousedown', onDown)
    return () => window.removeEventListener('mousedown', onDown)
  }, [open])

  function handleOpen() {
    if (!triggerRef.current) return
    const r = triggerRef.current.getBoundingClientRect()
    setPos({ top: r.bottom + 4, left: r.left })
    setOpen((o) => !o)
  }

  return (
    <>
      <div ref={triggerRef} onClick={handleOpen} className="inline-flex items-center">
        {children}
      </div>

      {open && createPortal(
        <div
          ref={popRef}
          style={{ position: 'fixed', top: pos.top, left: pos.left, zIndex: 99999 }}
          className="grid max-h-72 w-72 grid-cols-6 gap-1 overflow-y-auto rounded-lg border border-border bg-background p-2 shadow-xl"
        >
          {ALL_SHAPES.map((shape) => (
            <button
              key={shape}
              title={SHAPE_LABELS[shape]}
              className="flex h-10 w-10 items-center justify-center rounded border hover:border-border hover:bg-accent"
              style={{
                borderColor: shape === selectedShapeType ? 'hsl(var(--primary))' : 'transparent',
                backgroundColor: shape === selectedShapeType ? 'hsl(var(--primary)/0.12)' : undefined,
              }}
              onClick={() => { onSelect(shape); setOpen(false) }}
            >
              <svg viewBox="0 0 48 40" width="36" height="30" fill="none" stroke="currentColor" strokeWidth="2">
                {shape === 'ellipse' || shape === 'flowchart-connector'
                  ? <ellipse cx="24" cy="20" rx="20" ry="16" />
                  : shape === 'thought-bubble'
                    ? (
                      <g fill="currentColor" fillOpacity="0.15" stroke="currentColor" strokeWidth="2">
                        <rect x="2" y="2" width="44" height="27" rx="10" ry="8" />
                        <circle cx="11" cy="33" r="2.5" />
                        <circle cx="5" cy="38" r="1.5" />
                      </g>
                    )
                    : SHAPE_ICONS[shape]
                      ? shape === 'line' || shape === 'connector'
                        ? <path d={SHAPE_ICONS[shape]} strokeWidth="2" />
                        : <path d={SHAPE_ICONS[shape]} fill="currentColor" fillOpacity="0.15" />
                      : <rect x="4" y="8" width="40" height="24" />
                }
              </svg>
            </button>
          ))}
        </div>,
        document.body,
      )}
    </>
  )
}

import { useState, useRef, useEffect } from 'react'
import { createPortal } from 'react-dom'

const MAX_COLS = 8
const MAX_ROWS = 8

interface Props {
  children: React.ReactNode
  pendingConfig?: { cols: number; rows: number } | null
  onSelect(cols: number, rows: number): void
}

export function TablePickerPopover({ children, pendingConfig, onSelect }: Props): JSX.Element {
  const [open, setOpen] = useState(false)
  const [hover, setHover] = useState({ col: 0, row: 0 })
  const [pos, setPos] = useState({ top: 0, left: 0 })
  const triggerRef = useRef<HTMLDivElement>(null)
  const popRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    if (!open) return
    function onDown(e: MouseEvent) {
      if (popRef.current?.contains(e.target as Node)) return
      if (triggerRef.current?.contains(e.target as Node)) return
      setOpen(false)
    }
    window.addEventListener('mousedown', onDown)
    return () => window.removeEventListener('mousedown', onDown)
  }, [open])

  function handleOpen() {
    if (!triggerRef.current) return
    const r = triggerRef.current.getBoundingClientRect()
    setPos({ top: r.bottom + 4, left: r.left })
    setOpen((o) => !o)
  }

  return (
    <>
      <div ref={triggerRef} onClick={handleOpen} className="inline-flex items-center">
        {children}
      </div>

      {open && createPortal(
        <div
          ref={popRef}
          style={{ position: 'fixed', top: pos.top, left: pos.left, zIndex: 99999 }}
          className="rounded-lg border border-border bg-background p-2 shadow-xl"
        >
          <div className="mb-1.5 text-center text-[11px] text-muted-foreground">
            {hover.col > 0 && hover.row > 0
              ? `${hover.col} × ${hover.row} table`
              : pendingConfig
                ? `${pendingConfig.cols} × ${pendingConfig.rows} (armed)`
                : 'Select table size'}
          </div>
          <div
            className="grid gap-0.5"
            style={{ gridTemplateColumns: `repeat(${MAX_COLS}, 20px)` }}
            onMouseLeave={() => setHover({ col: 0, row: 0 })}
          >
            {Array.from({ length: MAX_ROWS }, (_, r) =>
              Array.from({ length: MAX_COLS }, (_, c) => {
                const isHovered = r < hover.row && c < hover.col
                const isPending = hover.col === 0 && hover.row === 0 && pendingConfig && r < pendingConfig.rows && c < pendingConfig.cols
                return (
                  <button
                    key={`${r}-${c}`}
                    className="h-5 w-5 rounded-[2px] border"
                    style={{
                      borderColor: isHovered || isPending ? 'hsl(var(--primary))' : 'hsl(var(--border))',
                      background: isHovered || isPending ? 'hsl(var(--primary)/0.15)' : 'transparent',
                    }}
                    onMouseEnter={() => setHover({ col: c + 1, row: r + 1 })}
                    onClick={() => { onSelect(c + 1, r + 1); setOpen(false) }}
                  />
                )
              })
            )}
          </div>
        </div>,
        document.body,
      )}
    </>
  )
}

