        }
      >
        {(close) => (
          <ChromeColorPicker
            color={element.fill || '#fef08a'}
            current={element.fill ?? ''}
            palette={FILL_PALETTE}
            onChange={(c) => onUpdate({ fill: c })}
            onPaletteSelect={(c) => onUpdate({ fill: c })}
            onReset={() => { onUpdate({ fill: undefined }); close() }}
            resetLabel="Remove fill"
          />
