          </Button>
        }
      >
        {(close) => (
          <ChromeColorPicker
            color={element.border?.color || '#000000'}
            current={(element.border?.width ?? 0) > 0 ? (element.border?.color ?? '') : ''}
            palette={themedColorPalette}
            onChange={(c) => onUpdate({ border: { color: c, width: element.border?.width || 1, style: element.border?.style ?? 'solid' } })}
            onPaletteSelect={(c) => onUpdate({ border: { color: c, width: element.border?.width || 1, style: element.border?.style ?? 'solid' } })}
            onReset={() => { onUpdate({ border: undefined }); close() }}
            resetLabel="Remove stroke"
          />
        )}
      </ColorPickerDropdown>

      {/* Stroke weight */}
      <BorderWeightPicker
        currentWidth={element.border?.width ?? 0}
        onApply={(w) => onUpdate({ border: w === undefined ? undefined : { color: element.border?.color ?? '#000000', width: w, style: element.border?.style ?? 'solid' } })}
      />

      <Separator orientation="vertical" className="mx-0.5 h-5" />

      {/* Text alignment */}
      {compact ? (
        <CompactGroup icon={AlignLeft} label="Text alignment">
          <Button variant="ghost" size="icon" className={cn('h-7 w-7', element.align === 'left' && '!text-primary')} onClick={() => onUpdate({ align: 'left' })}><AlignLeft className="h-3.5 w-3.5" /></Button>
          <Button variant="ghost" size="icon" className={cn('h-7 w-7', element.align === 'center' && '!text-primary')} onClick={() => onUpdate({ align: 'center' })}><AlignCenter className="h-3.5 w-3.5" /></Button>
          <Button variant="ghost" size="icon" className={cn('h-7 w-7', element.align === 'right' && '!text-primary')} onClick={() => onUpdate({ align: 'right' })}><AlignRight className="h-3.5 w-3.5" /></Button>
